import pg from "pg";
import crypto from "crypto";
const Pool = pg.Pool;
const pool = new Pool({ connectionString: process.env.PROD_DATABASE_URL || process.env.DATABASE_URL });
function hash(s: string): string { return crypto.createHash("md5").update(s.toLowerCase().trim()).digest("hex"); }
function q(e:string,b:string,d:number,s:string,o:string[],c:number,r:string,rs:string) {
  return {tier:"rn",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b,rs};
}

const QS = [
  // ============================================================
  // CANADA RN QUESTIONS (75) — exam: RN-CAT, region_scope: CAN
  // ============================================================

  // Fundamentals (CAN)
  q("RN-CAT","Fundamentals",2,"A nurse is performing a head-to-toe assessment on a newly admitted client. Which assessment technique should be performed first?","Inspection of the client before any physical contact|Palpation of all four quadrants|Percussion of the chest|Auscultation of heart sounds".split("|"),0,"Correct: Inspection is always the first step in physical assessment, allowing the nurse to observe general appearance, skin colour, symmetry, and any obvious abnormalities before touching the client. Incorrect: Palpation (B) follows inspection. Percussion (C) and auscultation (D) come after inspection and palpation. Exception: abdominal assessment uses inspection, auscultation, percussion, then palpation. Clinical Takeaway: Systematic assessment follows inspection → palpation → percussion → auscultation, except for the abdomen. Exam Pearl: The abdomen is the only body system where auscultation precedes percussion and palpation to avoid altering bowel sounds.","CAN"),
  q("RN-CAT","Fundamentals",2,"A nurse is delegating tasks to an unregulated care provider (UCP). Which task is appropriate to delegate?","Measuring and recording a stable client's vital signs|Assessing a postoperative wound for signs of infection|Administering oral medications to a client with dysphagia|Developing a nursing care plan for a newly admitted client".split("|"),0,"Correct: Vital signs on a stable client are within the UCP's scope when the client is stable and the RN provides clear direction. Incorrect: Wound assessment (B) requires clinical judgement and is an RN responsibility. Medication administration (C), especially for a client with dysphagia, requires nursing assessment. Care plan development (D) is an RN responsibility. Clinical Takeaway: Delegation follows the principles of right task, right circumstance, right person, right direction, and right supervision. Exam Pearl: In Canada, UCPs (health care aides, personal support workers) cannot perform assessments, administer medications, or make clinical judgements.","CAN"),
  q("RN-CAT","Fundamentals",3,"A client who recently immigrated to Canada refuses a blood transfusion based on religious beliefs. The health care team believes the transfusion is necessary. The nurse should:","Proceed with the transfusion as it is medically necessary|Respect the client's autonomous decision and document the refusal|Contact the ethics committee to override the client's decision|Convince the client that the medical team knows best".split("|"),1,"Correct: Client autonomy is a core principle in Canadian nursing ethics. Competent adults have the right to refuse treatment, including life-saving interventions, based on informed consent principles. Incorrect: Proceeding without consent (A) is battery. Ethics committees (C) cannot override client autonomy. Persuasion that dismisses client values (D) violates ethical practice. Clinical Takeaway: The Canadian Nurses Association Code of Ethics upholds autonomy, dignity, and the right to informed consent. Exam Pearl: Document the refusal, ensure the client understands the consequences, and provide alternative care options when possible.","CAN"),
  q("RN-CAT","Fundamentals",2,"When applying the nursing process, which step comes immediately after assessment?","Planning appropriate nursing interventions|Diagnosis — identifying the client's health problems|Implementation of the care plan|Evaluation of outcomes".split("|"),1,"Correct: The nursing process follows: Assessment → Diagnosis → Planning → Implementation → Evaluation (ADPIE). After collecting assessment data, the nurse analyses the data and identifies nursing diagnoses. Incorrect: Planning (A) follows diagnosis. Implementation (C) follows planning. Evaluation (D) is the final step. Clinical Takeaway: The nursing process is a systematic, evidence-based framework for providing client-centred care. Exam Pearl: Remember ADPIE — each step must be completed sequentially, though the process is ongoing and cyclical.","CAN"),

  // Advanced Assessment (CAN)
  q("RN-CAT","Advanced Assessment",3,"During auscultation, the nurse hears a friction rub over the left lower sternal border that increases with leaning forward. This is most consistent with:","Mitral regurgitation|Pericardial friction rub|Pleural effusion|Normal heart sound variant".split("|"),1,"Correct: Pericardial friction rubs are scratchy, high-pitched sounds heard best at the left lower sternal border with the client leaning forward. They indicate pericardial inflammation. Incorrect: Mitral regurgitation (A) produces a holosystolic murmur at the apex. Pleural effusion (C) causes decreased breath sounds, not cardiac friction sounds. This is not a normal variant (D). Clinical Takeaway: Pericardial friction rubs have three components corresponding to atrial systole, ventricular systole, and ventricular diastole. Exam Pearl: Differentiate pericardial rubs from pleural rubs — pericardial rubs persist when the client holds their breath, pleural rubs do not.","CAN"),
  q("RN-CAT","Advanced Assessment",4,"A nurse performing a cranial nerve assessment notes the client cannot raise their eyebrows or close their eyes tightly on the right side. This indicates dysfunction of:","CN V (trigeminal nerve)|CN VII (facial nerve)|CN III (oculomotor nerve)|CN XII (hypoglossal nerve)".split("|"),1,"Correct: CN VII (facial nerve) controls facial expression muscles. Inability to raise eyebrows and close eyes on one side indicates peripheral CN VII palsy (Bell palsy). Incorrect: CN V (A) controls facial sensation and mastication. CN III (C) controls eye movement and pupil constriction. CN XII (D) controls tongue movement. Clinical Takeaway: Upper motor neuron lesions spare the forehead (bilateral innervation), while lower motor neuron lesions affect the entire ipsilateral face. Exam Pearl: Bell palsy affects the entire side of the face including the forehead, distinguishing it from stroke-related facial weakness.","CAN"),

  // Pharmacology (CAN)
  q("RN-CAT","Pharmacology",2,"A client prescribed warfarin asks about dietary considerations. The nurse should advise:","Avoid all green vegetables entirely|Maintain consistent vitamin K intake from day to day|Increase vitamin K intake to enhance the drug's effectiveness|There are no dietary restrictions with warfarin".split("|"),1,"Correct: Vitamin K counteracts warfarin. Clients should maintain a consistent daily intake rather than eliminating vitamin K–rich foods, which allows for stable INR levels. Incorrect: Complete avoidance (A) is unnecessary and nutritionally harmful. Increasing vitamin K (C) would decrease warfarin's effect. Warfarin does have dietary considerations (D). Clinical Takeaway: Educate clients about vitamin K consistency rather than elimination, and the importance of regular INR monitoring. Exam Pearl: Foods high in vitamin K include dark leafy greens (kale, spinach, broccoli), green tea, and liver.","CAN"),
  q("RN-CAT","Pharmacology",3,"A client taking metoprolol reports a heart rate of 52 bpm and dizziness upon standing. The nurse should:","Hold the medication and notify the prescriber about symptomatic bradycardia|Administer the medication as prescribed since the heart rate is close to normal|Instruct the client to take the medication with orange juice|Double the next dose to prevent rebound hypertension".split("|"),0,"Correct: Metoprolol (beta-blocker) commonly causes bradycardia and orthostatic hypotension. A heart rate below 60 bpm with symptoms warrants holding the dose and contacting the prescriber for dose adjustment. Incorrect: Administering despite symptomatic bradycardia (B) could worsen the condition. Orange juice (C) does not affect beta-blocker absorption. Doubling the dose (D) would exacerbate the problem. Clinical Takeaway: Always assess apical pulse for 60 seconds before administering beta-blockers. Hold if HR < 60 bpm or SBP < 90 mmHg and notify the prescriber. Exam Pearl: Rebound tachycardia can occur with abrupt discontinuation, so beta-blockers should be tapered gradually.","CAN"),
  q("RN-CAT","Pharmacology",4,"A nurse is managing a client receiving continuous IV heparin infusion. The aPTT result is 120 seconds (therapeutic range 60–80 seconds). The nurse should:","Continue the infusion and recheck in 6 hours|Stop the infusion, notify the prescriber, and have protamine sulfate available|Decrease the rate by half and recheck in 4 hours|Administer vitamin K to reverse the heparin effect".split("|"),1,"Correct: An aPTT of 120 seconds is supratherapeutic and indicates a high bleeding risk. The infusion should be stopped, the prescriber notified, and protamine sulfate (heparin antidote) should be available. Incorrect: Continuing (A) risks serious haemorrhage. Decreasing by half (C) may still be excessive and the prescriber must be consulted. Vitamin K (D) reverses warfarin, not heparin. Clinical Takeaway: Protamine sulfate reverses heparin; 1 mg neutralizes approximately 100 units of heparin. Exam Pearl: Know the antidote pairs — protamine for heparin, vitamin K/PCC for warfarin, idarucizumab for dabigatran.","CAN"),

  // Cardiovascular (CAN)
  q("RN-CAT","Cardiovascular",3,"A client with a mechanical heart valve is prescribed lifelong warfarin therapy. The target INR range is:","1.0–1.5|2.5–3.5|2.0–3.0|4.0–5.0".split("|"),1,"Correct: Mechanical heart valves require higher-intensity anticoagulation with a target INR of 2.5–3.5 due to the high thrombotic risk of mechanical prostheses. Incorrect: 1.0–1.5 (A) is subtherapeutic. 2.0–3.0 (C) is the standard range for atrial fibrillation and DVT, but insufficient for mechanical valves. 4.0–5.0 (D) is excessively high and increases bleeding risk. Clinical Takeaway: Bioprosthetic valves may only require anticoagulation for 3–6 months, while mechanical valves require lifelong therapy. Exam Pearl: Aortic mechanical valves may have a slightly lower INR target (2.0–3.0) than mitral mechanical valves (2.5–3.5) depending on guidelines.","CAN"),
  q("RN-CAT","Cardiovascular",2,"A nurse is educating a client about modifiable risk factors for coronary artery disease. Which factor listed is modifiable?","Age over 65 years|Hyperlipidaemia|Family history of heart disease|Male sex".split("|"),1,"Correct: Hyperlipidaemia is modifiable through diet, exercise, and medication (statins). Incorrect: Age (A), family history (C), and sex (D) are non-modifiable risk factors. Other modifiable factors include hypertension, smoking, diabetes, obesity, and sedentary lifestyle. Clinical Takeaway: Aggressive management of modifiable risk factors significantly reduces cardiovascular morbidity and mortality. Exam Pearl: The Canadian Cardiovascular Society recommends statin therapy for individuals with ≥ 20% 10-year Framingham risk score.","CAN"),

  // Respiratory (CAN)
  q("RN-CAT","Respiratory",3,"A client with COPD is receiving oxygen via nasal prongs at 2 L/min. The nurse understands the rationale for low-flow oxygen is:","High-flow oxygen will damage the lungs|COPD clients rely on hypoxic drive, and high oxygen may suppress respiratory effort|Low-flow oxygen costs less in Canadian health care|There is no difference between low and high flow in COPD".split("|"),1,"Correct: Chronic CO₂ retention in some COPD clients shifts their respiratory drive from CO₂-mediated to hypoxic drive. High-concentration oxygen can suppress this drive, causing hypoventilation and CO₂ narcosis. Incorrect: High-flow oxygen does not directly damage lungs (A). Cost (C) is not the clinical rationale. There is a significant clinical difference (D). Clinical Takeaway: Target SpO₂ of 88–92% in COPD clients to maintain adequate oxygenation without suppressing respiratory drive. Exam Pearl: Not all COPD clients are CO₂ retainers — those with chronic hypercapnia are most at risk.","CAN"),
  q("RN-CAT","Respiratory",2,"A client is using a metered-dose inhaler (MDI) without a spacer. The nurse identifies correct technique when the client:","Inhales rapidly and deeply while pressing the canister|Exhales fully, then inhales slowly and deeply while pressing the canister, holding breath for 10 seconds|Inhales through the nose while pressing the canister|Presses the canister and then begins to inhale 5 seconds later".split("|"),1,"Correct: Proper MDI technique: exhale fully, place mouthpiece between lips, inhale slowly and deeply while pressing the canister, then hold breath for 10 seconds to allow medication deposition. Incorrect: Rapid inhalation (A) causes medication to hit the back of the throat. Nasal inhalation (C) does not deliver medication to the lungs. Delayed inhalation (D) results in lost medication. Clinical Takeaway: A spacer device improves drug delivery by 40–60% and is recommended for all MDI users. Exam Pearl: Wait 1–2 minutes between puffs if using the same inhaler; use bronchodilator before corticosteroid inhaler.","CAN"),

  // Renal (CAN)
  q("RN-CAT","Renal",3,"A client with chronic kidney disease stage 4 has a phosphorus level of 2.1 mmol/L (elevated). The nurse anticipates the prescription of:","Calcium acetate (phosphate binder) with meals|Phosphorus supplements|High-phosphorus diet|IV calcium infusion".split("|"),0,"Correct: Elevated phosphorus in CKD requires phosphate binders (calcium acetate, sevelamer) taken WITH meals to bind dietary phosphorus in the GI tract and prevent absorption. Incorrect: Phosphorus supplements (B) would worsen hyperphosphataemia. High-phosphorus diet (C) is contraindicated. IV calcium (D) does not treat the underlying phosphorus retention. Clinical Takeaway: CKD clients should follow a low-phosphorus diet (limit dairy, processed foods, cola). Exam Pearl: Hyperphosphataemia leads to reciprocal hypocalcaemia, stimulating PTH release and causing renal osteodystrophy.","CAN"),
  q("RN-CAT","Renal",4,"A client on haemodialysis reports muscle cramps and hypotension during the session. The nurse suspects:","Infection of the vascular access|Excessive ultrafiltration rate causing intravascular volume depletion|Allergic reaction to the dialysate|Air embolism".split("|"),1,"Correct: Rapid fluid removal (ultrafiltration) during haemodialysis causes intravascular volume depletion, leading to hypotension, muscle cramps, nausea, and dizziness. Incorrect: Infection (A) presents with fever and local signs. Allergic reactions (C) cause urticaria and respiratory symptoms. Air embolism (D) causes dyspnoea and chest pain. Clinical Takeaway: Slow the ultrafiltration rate, administer normal saline bolus, and place the client in Trendelenburg position. Exam Pearl: Clients should limit fluid gain between dialysis sessions to < 2–3 kg to minimize intradialytic complications.","CAN"),

  // Endocrine (CAN)
  q("RN-CAT","Endocrine",3,"A client with newly diagnosed type 1 diabetes is learning to self-administer insulin. The nurse teaches that rapid-acting insulin (lispro) should be injected:","30 minutes before meals|Within 15 minutes before eating|At bedtime only|2 hours after meals".split("|"),1,"Correct: Rapid-acting insulins (lispro, aspart, glulisine) have onset within 10–15 minutes and should be injected within 15 minutes before meals to match postprandial glucose rise. Incorrect: 30 minutes before meals (A) is the timing for regular (short-acting) insulin. Bedtime (C) would cause nocturnal hypoglycaemia. Post-meal (D) is too late for optimal glucose control. Clinical Takeaway: Rapid-acting insulin peaks at 1–2 hours and lasts 3–5 hours, closely mimicking physiological insulin release. Exam Pearl: In Canada, insulin is measured in units — 1 unit lowers blood glucose by approximately 2–3 mmol/L (varies by individual).","CAN"),
  q("RN-CAT","Endocrine",2,"A nurse suspects a client with Addison disease is experiencing an adrenal crisis. Which finding supports this?","Hypertension with bounding pulses|Severe hypotension, dehydration, and hypoglycaemia|Hyperglycaemia with polyuria|Weight gain and oedema".split("|"),1,"Correct: Adrenal crisis presents with severe hypotension (from cortisol and aldosterone deficiency), dehydration, hypoglycaemia, hyperkalemia, and hyponatraemia. This is a medical emergency. Incorrect: Hypertension (A) is opposite to expected findings. Hyperglycaemia (C) is associated with cortisol excess (Cushing), not deficiency. Weight gain and oedema (D) suggest cortisol or aldosterone excess. Clinical Takeaway: Immediate treatment includes IV hydrocortisone 100 mg bolus, aggressive IV normal saline, and dextrose for hypoglycaemia. Exam Pearl: Clients with Addison disease must carry a medical alert identification and emergency hydrocortisone injection kit.","CAN"),

  // GI (CAN)
  q("RN-CAT","Gastrointestinal",3,"A client with Crohn disease asks about the difference from ulcerative colitis. The nurse explains that Crohn disease:","Affects only the rectum and colon|Can affect any part of the GI tract from mouth to anus and involves all bowel wall layers (transmural)|Always requires colectomy for treatment|Is limited to the mucosal layer of the colon".split("|"),1,"Correct: Crohn disease is transmural inflammation that can affect any GI segment (most commonly the terminal ileum), with skip lesions and potential complications including fistulae, strictures, and abscesses. Incorrect: Only rectum/colon (A) describes UC. Colectomy (C) is curative for UC but not Crohn. Mucosal layer only (D) describes UC pathology. Clinical Takeaway: Crohn disease has no surgical cure; treatment focuses on inducing and maintaining remission with immunomodulators and biologics. Exam Pearl: Cobblestone mucosa, granulomas, and skip lesions are histological hallmarks of Crohn disease.","CAN"),
  q("RN-CAT","Gastrointestinal",2,"A client with a nasogastric tube connected to intermittent suction reports nausea. The nurse should first:","Remove the NG tube immediately|Verify tube patency and check for kinks or blockage|Administer an antiemetic without assessment|Increase the suction pressure to maximum".split("|"),1,"Correct: Nausea with an NG tube may indicate tube obstruction, displacement, or incorrect suction. First, verify patency by checking for kinks, irrigation, and correct placement. Incorrect: Removing the tube (A) is premature. Antiemetic without assessment (C) does not address the cause. Maximum suction (D) can damage gastric mucosa. Clinical Takeaway: Irrigate NG tubes with 30 mL normal saline every 4 hours or as ordered to maintain patency. Exam Pearl: Never irrigate or reposition an NG tube in a client who has had gastric or oesophageal surgery without a prescriber order.","CAN"),

  // Neurological (CAN)
  q("RN-CAT","Neurological",3,"A client admitted with a subarachnoid haemorrhage is placed on nimodipine. The nurse understands this medication is given to:","Reduce blood pressure|Prevent cerebral vasospasm|Dissolve the intracranial clot|Control seizures".split("|"),1,"Correct: Nimodipine is a calcium channel blocker that selectively dilates cerebral arteries, preventing vasospasm which peaks at days 4–14 post-SAH. It improves neurological outcomes but does not significantly lower systemic BP at standard doses. Incorrect: BP reduction (A) is not the primary goal. It does not dissolve clots (C) or control seizures (D). Clinical Takeaway: Nimodipine 60 mg every 4 hours for 21 days is standard prophylaxis. Administer on time — missed doses reduce efficacy. Exam Pearl: Nimodipine is given orally or via NG tube — it must never be given intravenously as it can cause severe hypotension and cardiac arrest.","CAN"),
  q("RN-CAT","Neurological",4,"A client with a spinal cord injury at C5 has preserved biceps function but absent wrist extension. The nurse expects the client will:","Breathe independently but need assistance with fine motor tasks|Require full ventilatory support|Have full upper extremity function|Be unable to move any extremities".split("|"),0,"Correct: C5 injury preserves diaphragm function (C3–C5) and shoulder/elbow flexion (biceps C5–C6) but loses wrist extension (C6), hand function (C7–T1), and all trunk/lower extremity function. The client breathes independently but needs extensive ADL assistance. Incorrect: Full ventilatory support (B) is for C3 and above injuries. Full upper extremity (C) requires intact C5–T1. Complete quadriplegia without arm movement (D) is C4 and above. Clinical Takeaway: Functional level determines rehabilitation goals — C5 clients can power a wheelchair with hand controls and perform some feeding with assistive devices. Exam Pearl: Spinal cord injury level = lowest segment with intact motor and sensory function.","CAN"),

  // Musculoskeletal (CAN)
  q("RN-CAT","Musculoskeletal",2,"A client with a fractured femur develops sudden onset dyspnoea, tachycardia, and petechial rash on the chest 48 hours after injury. The nurse suspects:","Pulmonary embolism from DVT|Fat embolism syndrome|Pneumothorax|Allergic reaction to medication".split("|"),1,"Correct: Fat embolism syndrome typically occurs 24–72 hours after long bone fractures. The classic triad is respiratory distress, neurological changes, and petechial rash (unique to fat emboli, not seen in PE). Incorrect: PE (A) does not cause petechial rash. Pneumothorax (C) presents with unilateral absent breath sounds. Allergic reaction (D) presents with urticaria, not petechiae. Clinical Takeaway: Prevention includes early fracture immobilisation and adequate hydration. Treatment is supportive with oxygen and possible mechanical ventilation. Exam Pearl: The petechial rash in fat embolism appears on the chest, axillae, and conjunctivae — this distinguishes it from thromboembolic PE.","CAN"),
  q("RN-CAT","Musculoskeletal",3,"A client post-hip replacement should be positioned to prevent prosthetic dislocation. The nurse ensures:","The affected leg is adducted past midline|The affected leg is maintained in abduction with an abduction pillow, avoiding flexion beyond 90 degrees|The client sits in a low chair to rest|The hip is flexed to 120 degrees for comfort".split("|"),1,"Correct: After posterior-approach hip replacement, maintain hip abduction (avoid adduction past midline), avoid hip flexion > 90 degrees, and avoid internal rotation to prevent posterior dislocation. Incorrect: Adduction past midline (A) risks dislocation. Low chairs (C) flex the hip excessively. Flexion to 120 degrees (D) exceeds the safe limit. Clinical Takeaway: Use a raised toilet seat, avoid crossing legs, and do not bend more than 90 degrees at the hip. Exam Pearl: Anterior-approach hip replacements have fewer positioning restrictions but still require precautions during the healing period.","CAN"),

  // Hematology (CAN)
  q("RN-CAT","Hematology",3,"A client receiving chemotherapy has a platelet count of 18 × 10⁹/L. The nurse should implement:","Contact isolation precautions|Bleeding precautions including soft toothbrush, electric razor, and avoiding IM injections|Neutropenic precautions only|No special precautions at this level".split("|"),1,"Correct: Platelet count < 20 × 10⁹/L poses a high risk for spontaneous bleeding. Precautions include soft toothbrush, electric razor, avoiding IM injections, avoiding rectal temperatures, applying pressure to venipuncture sites, and monitoring for signs of internal bleeding. Incorrect: Contact isolation (A) is not indicated for thrombocytopenia. Neutropenic precautions (C) address low WBCs, not platelets. This level absolutely requires precautions (D). Clinical Takeaway: Platelet transfusion is indicated if platelets < 10 × 10⁹/L or if actively bleeding with platelets < 50 × 10⁹/L. Exam Pearl: In Canada, platelets are measured as × 10⁹/L (normal: 150–400 × 10⁹/L), equivalent to × 10³/μL in US units.","CAN"),

  // Oncology (CAN)
  q("RN-CAT","Oncology",3,"A client with cancer is receiving palliative care. The family asks if the client will still receive treatment. The nurse explains that palliative care:","Means the client has chosen to stop all treatment|Focuses on symptom management and quality of life and can occur alongside curative treatment|Is only provided in the last days of life|Replaces all nursing care with comfort measures only".split("|"),1,"Correct: Palliative care addresses physical, psychosocial, and spiritual needs and can be integrated at any stage of illness, alongside curative or disease-modifying treatment. It is not limited to end-of-life care. Incorrect: Palliative care does not mean stopping treatment (A). It is not limited to the last days (C). It encompasses comprehensive nursing care (D), not just comfort measures. Clinical Takeaway: In Canada, Medical Assistance in Dying (MAiD) is distinct from palliative care and has specific eligibility criteria under federal legislation. Exam Pearl: The Canadian Hospice Palliative Care Association promotes early integration of palliative care for all individuals with life-limiting illness.","CAN"),
  q("RN-CAT","Oncology",4,"A client undergoing radiation therapy to the chest develops radiation pneumonitis. The nurse should anticipate:","Antibiotic therapy as first-line|Corticosteroid therapy to reduce pulmonary inflammation|Immediate surgical resection of the affected lobe|Increased radiation dose to treat the inflammation".split("|"),1,"Correct: Radiation pneumonitis (occurring 1–6 months post-radiation) is an inflammatory reaction treated with systemic corticosteroids (prednisone) with a gradual taper over weeks. Incorrect: Antibiotics (A) do not treat radiation-induced inflammation. Surgery (C) is not indicated. Increasing radiation (D) would worsen the damage. Clinical Takeaway: Symptoms include dyspnoea, dry cough, and low-grade fever. Progressive fibrosis may develop months later. Exam Pearl: Radiation recall is a different phenomenon — it is a skin reaction in a previously irradiated field triggered by subsequent chemotherapy.","CAN"),

  // Infection Control (CAN)
  q("RN-CAT","Infection Control",2,"A nurse is caring for a client with active pulmonary tuberculosis. Which personal protective equipment is required?","Surgical mask and gloves|Fitted N95 respirator|Gown and gloves only|Face shield only".split("|"),1,"Correct: Active pulmonary TB requires airborne precautions with an N95 respirator (fit-tested) and a negative-pressure isolation room. TB is transmitted via airborne droplet nuclei (< 5 μm) that remain suspended in the air. Incorrect: A surgical mask (A) does not filter small airborne particles. Gown and gloves alone (C) are contact precautions. A face shield (D) protects against splashes, not airborne organisms. Clinical Takeaway: The client wears a surgical mask during transport outside the negative-pressure room. Exam Pearl: N95 respirators must be fit-tested annually; healthcare workers with positive TB skin tests require chest X-ray rather than repeat testing.","CAN"),
  q("RN-CAT","Infection Control",3,"A nurse sustains a needlestick injury from a client with unknown HIV status. The priority action is:","Wait for the source client's HIV test results before taking action|Immediately wash the site with soap and water and report the exposure for post-exposure prophylaxis assessment|Apply a tourniquet above the injury site|Apply alcohol-based hand rub to the wound".split("|"),1,"Correct: Immediate wound cleansing and prompt reporting allows assessment for post-exposure prophylaxis (PEP), which should ideally be started within 2 hours (and no later than 72 hours) of exposure. Incorrect: Waiting for results (A) delays critical PEP initiation. A tourniquet (C) is not indicated. Alcohol on an open wound (D) does not replace proper cleansing and is painful. Clinical Takeaway: PEP typically involves a 28-day course of antiretroviral medications. Baseline testing of the exposed worker is performed at the time of exposure. Exam Pearl: In Canada, needlestick injuries are reported under workplace health and safety legislation, and source client testing requires informed consent.","CAN"),

  // Fluid/Electrolytes (CAN)
  q("RN-CAT","Fluid/Electrolytes",3,"A client's serum sodium is 128 mmol/L. The nurse recognizes this as hyponatraemia and monitors for:","Muscle rigidity and hyperreflexia|Confusion, headache, nausea, and possible seizures|Peaked T waves on ECG|Chvostek sign".split("|"),1,"Correct: Hyponatraemia (< 135 mmol/L) causes cerebral oedema leading to neurological symptoms: confusion, headache, nausea, lethargy, and seizures in severe cases (< 120 mmol/L). Incorrect: Muscle rigidity and hyperreflexia (A) are more associated with hypocalcaemia. Peaked T waves (C) indicate hyperkalaemia. Chvostek sign (D) is positive in hypocalcaemia. Clinical Takeaway: Correction must not exceed 8–10 mmol/L per 24 hours to prevent osmotic demyelination syndrome. Exam Pearl: SIADH and excessive hypotonic fluid administration are common causes of hyponatraemia in hospitalised clients.","CAN"),
  q("RN-CAT","Fluid/Electrolytes",2,"A client with hypokalaemia (K⁺ 2.8 mmol/L) is prescribed IV potassium chloride. The nurse should:","Administer potassium by IV push for rapid correction|Dilute and infuse at no more than 10–20 mmol/hour via an infusion pump with cardiac monitoring|Add potassium to a dextrose solution without monitoring|Administer potassium intramuscularly".split("|"),1,"Correct: IV potassium must never be given by push (risk of fatal cardiac arrest). It is diluted, infused via pump at ≤ 10–20 mmol/hour, with continuous cardiac monitoring for arrhythmias. Incorrect: IV push (A) causes fatal cardiac arrest. Without monitoring (C) is unsafe. IM administration (D) is not a route for potassium. Clinical Takeaway: Peripheral IV potassium concentration should not exceed 40 mmol/L to prevent phlebitis. Higher concentrations require a central line. Exam Pearl: Always verify potassium concentration and rate with another nurse — potassium is a high-alert medication.","CAN"),

  // Acid-Base (CAN)
  q("RN-CAT","Acid-Base",3,"A client has ABG results: pH 7.30, PaCO₂ 55 mmHg, HCO₃⁻ 24 mmol/L. The nurse interprets this as:","Metabolic acidosis|Uncompensated respiratory acidosis|Compensated metabolic alkalosis|Respiratory alkalosis".split("|"),1,"Correct: pH < 7.35 (acidosis), PaCO₂ > 45 (respiratory cause), HCO₃⁻ is normal (24) indicating the kidneys have not yet compensated. This is uncompensated respiratory acidosis. Incorrect: Metabolic acidosis (A) would show low HCO₃⁻. Metabolic alkalosis (C) would show elevated pH. Respiratory alkalosis (D) would have low PaCO₂. Clinical Takeaway: Causes include hypoventilation from CNS depression, COPD exacerbation, or neuromuscular disease. Treatment addresses the underlying cause and supports ventilation. Exam Pearl: Use the ROME mnemonic — Respiratory Opposite (pH and PaCO₂ move in opposite directions), Metabolic Equal (pH and HCO₃⁻ move together).","CAN"),

  // Diabetes (CAN)
  q("RN-CAT","Diabetes",3,"A client with type 1 diabetes has a blood glucose of 2.8 mmol/L and is conscious. The nurse should:","Administer IV dextrose 50% immediately|Give 15 g of fast-acting carbohydrate (e.g., 150 mL juice), recheck in 15 minutes|Administer 1 mg glucagon IM|Hold all insulin and observe without treatment".split("|"),1,"Correct: For conscious hypoglycaemia, the '15-15 Rule' applies: give 15 g of simple carbohydrate, recheck glucose in 15 minutes, and repeat if still < 4.0 mmol/L. Then provide a complex carbohydrate/protein snack. Incorrect: IV dextrose (A) is for unconscious clients or when IV access is available and oral intake is not possible. Glucagon IM (C) is for unconscious clients without IV access. Observation without treatment (D) is dangerous. Clinical Takeaway: In Canada, hypoglycaemia is defined as blood glucose < 4.0 mmol/L by Diabetes Canada guidelines. Exam Pearl: One serving of fast-acting carbs = 15 g: 150 mL juice, 3–4 glucose tablets, 15 mL (1 tbsp) honey or sugar.","CAN"),
  q("RN-CAT","Diabetes",2,"A nurse is teaching a client with type 2 diabetes about foot care. Which instruction is most important?","Soak feet in hot water daily to improve circulation|Inspect feet daily for cuts, blisters, or colour changes|Trim toenails in a rounded shape|Walk barefoot indoors to toughen the feet".split("|"),1,"Correct: Daily foot inspection is essential because peripheral neuropathy reduces sensation, and clients may not feel injuries that can lead to infection and amputation. Incorrect: Hot water soaks (A) risk burns in clients with neuropathy. Rounded toenails (C) promote ingrown nails — cut straight across. Walking barefoot (D) increases injury risk. Clinical Takeaway: Clients with diabetes should also wear well-fitting shoes, keep skin moisturised (not between toes), and see a chiropodist/podiatrist regularly. Exam Pearl: Diabetic foot ulcers are the leading cause of non-traumatic lower-extremity amputations. Prevention is key.","CAN"),

  // Mental Health (CAN)
  q("RN-CAT","Mental Health",3,"A client admitted under an involuntary psychiatric assessment (Form 1 in Ontario) asks to leave. The nurse should:","Allow the client to leave as they have the right to refuse treatment|Explain the legal authority for the hold, the client's rights, and contact the treatment team|Physically restrain the client without explanation|Ignore the request and continue care without addressing it".split("|"),1,"Correct: Under provincial mental health legislation (e.g., Ontario's Mental Health Act), the nurse explains the legal basis for involuntary detention, informs the client of their right to a review board hearing and legal counsel, and notifies the treatment team. Incorrect: Allowing the client to leave (A) is not appropriate under an involuntary hold. Physical restraint without justification (C) violates rights. Ignoring the request (D) is disrespectful and unethical. Clinical Takeaway: Provincial mental health acts vary across Canada but all provide for client rights, review boards, and time-limited involuntary assessments. Exam Pearl: In Ontario, a Form 1 allows up to 72 hours of assessment; a Form 3 extends the involuntary period for up to 2 weeks.","CAN"),
  q("RN-CAT","Mental Health",4,"A nurse is using therapeutic communication with a client who is grieving. Which response is most therapeutic?","'I know exactly how you feel — I lost my mother last year too.'|'It sounds like you are carrying a lot of pain right now. Tell me more about what you are experiencing.'|'Don't worry, everything will be fine in time.'|'You need to stay strong for your family.'".split("|"),1,"Correct: This response uses reflection (acknowledging emotion) and an open-ended invitation to share, demonstrating empathy without minimising the client's experience. Incorrect: Self-disclosure about similar loss (A) shifts focus to the nurse. False reassurance (C) minimises the client's grief. Advising to 'stay strong' (D) invalidates their emotional experience. Clinical Takeaway: Therapeutic communication involves active listening, empathy, open-ended questions, and silence — not advice-giving, false reassurance, or self-disclosure. Exam Pearl: Avoid 'why' questions as they can feel accusatory — replace with 'what' or 'how' questions.","CAN"),

  // Pediatrics (CAN)
  q("RN-CAT","Pediatrics",2,"A nurse is assessing a 6-month-old infant's developmental milestones. Which finding would require further evaluation?","The infant can sit with support|The infant does not roll over from back to front|The infant does not respond to sounds or voices|The infant mouths objects".split("|"),2,"Correct: By 6 months, infants should respond to sounds and voices (localise sound, turn toward voices). Absent response suggests hearing impairment requiring audiological evaluation. Incorrect: Sitting with support (A) is appropriate at 6 months. Rolling may vary (B) — some infants roll later. Mouthing objects (D) is normal exploratory behaviour at this age. Clinical Takeaway: Developmental surveillance should occur at every well-child visit. The Nipissing District Developmental Screen (NDDS) is used across Canada. Exam Pearl: Red flags for hearing: no startle to loud sounds at birth, no babbling by 9 months, no response to name by 12 months.","CAN"),
  q("RN-CAT","Pediatrics",3,"A child with croup presents with inspiratory stridor, barking cough, and mild retractions. The nurse anticipates treatment with:","IV antibiotics|Cool mist and a single dose of oral dexamethasone|Immediate intubation|Racemic epinephrine only".split("|"),1,"Correct: Mild to moderate croup is treated with cool mist humidification and oral dexamethasone (0.6 mg/kg × 1 dose) to reduce laryngeal oedema. Incorrect: Antibiotics (A) are not indicated as croup is viral (parainfluenza). Intubation (C) is reserved for severe respiratory failure. Racemic epinephrine (D) is added for moderate-to-severe croup with significant stridor at rest. Clinical Takeaway: Croup typically affects children 6 months to 3 years. The Westley croup score guides severity assessment and treatment. Exam Pearl: Drooling, high fever, and toxic appearance suggest epiglottitis (now rare with Hib vaccine), not croup — do not examine the throat.","CAN"),

  // Maternity/OB (CAN)
  q("RN-CAT","Maternity/OB",3,"A primigravida at 32 weeks gestation presents with painless bright red vaginal bleeding. The nurse suspects:","Placental abruption|Placenta praevia|Cervical insufficiency|Bloody show indicating labour onset".split("|"),1,"Correct: Painless bright red vaginal bleeding in the third trimester is the hallmark of placenta praevia (placenta covering or near the cervical os). Digital vaginal examination is absolutely contraindicated. Incorrect: Abruption (A) presents with painful dark red bleeding and uterine rigidity. Cervical insufficiency (C) typically presents earlier with painless cervical dilation. Bloody show (D) is a small amount of blood-tinged mucus. Clinical Takeaway: Diagnosis is confirmed by transabdominal ultrasound. Management includes bed rest, fetal monitoring, and planned caesarean delivery if placenta remains praevia at term. Exam Pearl: The three Ps of placenta praevia: Painless, Periodic, Profuse bright red bleeding.","CAN"),
  q("RN-CAT","Maternity/OB",2,"A nurse is monitoring a client in active labour. Which finding indicates the need for immediate intervention?","Cervical dilation of 6 cm|Fetal heart rate of 80 bpm for 3 minutes (prolonged bradycardia)|Contractions every 3 minutes lasting 60 seconds|Bloody show".split("|"),1,"Correct: Prolonged fetal bradycardia (< 110 bpm for > 2 minutes) indicates fetal distress and requires immediate intervention: position change, oxygen, IV fluid bolus, discontinue oxytocin, notify the provider, and prepare for possible emergency delivery. Incorrect: 6 cm dilation (A) is normal active labour. Regular contractions (C) are expected. Bloody show (D) is a normal labour sign. Clinical Takeaway: Normal fetal heart rate is 110–160 bpm. Bradycardia may result from cord compression, placental abruption, or uterine hyperstimulation. Exam Pearl: VEAL CHOP helps interpret FHR patterns: Variable decelerations = Cord compression, Early = Head compression, Accelerations = OK, Late = Placental insufficiency.","CAN"),

  // Postpartum/Newborn (CAN)
  q("RN-CAT","Postpartum/Newborn",2,"A nurse assesses a 12-hour-old newborn and notes a yellow tinge to the skin and sclera. The nurse should:","Recognise this as physiological jaundice which is normal|Report immediately as jaundice within the first 24 hours is pathological|Increase breastfeeding and reassess in 3 days|Apply phototherapy lights without a prescriber order".split("|"),1,"Correct: Jaundice appearing within the first 24 hours of life is always pathological (haemolytic disease, ABO/Rh incompatibility, infection) and requires immediate investigation including serum bilirubin, blood type, Coombs test, and CBC. Incorrect: Physiological jaundice (A) appears after 24 hours, typically peaking at days 3–5. While increased feeding helps (C), pathological jaundice requires urgent investigation. Phototherapy requires a prescriber order (D). Clinical Takeaway: Pathological jaundice within 24 hours is an emergency — untreated severe hyperbilirubinaemia can cause kernicterus (bilirubin encephalopathy). Exam Pearl: In Canada, the transcutaneous bilirubinometer is used for screening; serum bilirubin confirms diagnosis using the Bhutani nomogram.","CAN"),
  q("RN-CAT","Postpartum/Newborn",3,"A nurse is teaching a postpartum client about lochia changes. The expected sequence is:","Lochia alba → lochia serosa → lochia rubra|Lochia rubra → lochia serosa → lochia alba|Lochia serosa → lochia rubra → lochia alba|Lochia rubra → lochia alba → lochia serosa".split("|"),1,"Correct: Normal lochia progression: rubra (red, days 1–3) → serosa (pinkish-brown, days 4–10) → alba (yellowish-white, days 10–14 up to 6 weeks). Incorrect: All other sequences (A, C, D) are in incorrect order. Clinical Takeaway: Abnormal findings include return to rubra after serosa (subinvolution), foul odour (infection), or large clots (retained products). Assess fundal height simultaneously — it should decrease 1 cm/day. Exam Pearl: Saturating more than one pad per hour or passing clots larger than a loonie (Canadian dollar coin) warrants immediate assessment for postpartum haemorrhage.","CAN"),

  // Geriatrics (CAN)
  q("RN-CAT","Geriatrics",2,"An elderly client in a long-term care facility is at risk for falls. The nurse's priority intervention is:","Apply bilateral wrist restraints|Perform an individualized fall risk assessment and implement targeted prevention strategies|Keep the client in bed at all times|Sedate the client at bedtime".split("|"),1,"Correct: Individualised fall risk assessment (Morse Fall Scale, STRATIFY) guides targeted interventions: medication review, environmental modifications, exercise programs, vision assessment, and assistive devices. Incorrect: Restraints (A) increase injury risk and are a last resort requiring specific criteria in Canadian legislation. Bed rest (C) causes deconditioning. Sedation (D) increases fall risk. Clinical Takeaway: In Canada, restraint use is governed by provincial legislation and must follow a least-restraint approach with regular reassessment. Exam Pearl: The three most significant fall risk factors in older adults are a history of falls, gait/balance impairment, and polypharmacy.","CAN"),
  q("RN-CAT","Geriatrics",3,"A nurse suspects an elderly client in the community is being financially exploited by a family member. The nurse should:","Mind their own business as it is a family matter|Report the concern to the appropriate adult protection authority|Confront the family member directly|Wait until there is definitive proof before taking action".split("|"),1,"Correct: In most Canadian provinces, nurses have a duty to report suspected elder abuse (including financial exploitation) to adult protection services or the appropriate authority. Reporting is based on reasonable suspicion, not definitive proof. Incorrect: Ignoring the situation (A) violates professional and legal duty. Direct confrontation (C) may endanger the client. Waiting for proof (D) allows ongoing exploitation. Clinical Takeaway: Types of elder abuse include physical, emotional, sexual, financial, and neglect. Risk factors include social isolation, cognitive impairment, and caregiver stress. Exam Pearl: Under Canadian law, duty to report varies by province but all regulate protection of vulnerable adults through legislation.","CAN"),

  // Critical Care (CAN)
  q("RN-CAT","Critical Care",4,"A client in the ICU on a vasopressor infusion develops a central venous pressure (CVP) of 2 mmHg. The nurse interprets this as:","Normal fluid status|Low preload indicating volume depletion requiring fluid resuscitation|High preload requiring diuresis|An error in the transducer".split("|"),1,"Correct: CVP of 2 mmHg is below normal range (2–8 mmHg is low-normal), indicating hypovolaemia and inadequate right ventricular preload. Fluid resuscitation (crystalloid bolus) is indicated. Incorrect: Normal CVP is 2–8 mmHg, but in the context of vasopressor dependence, a CVP of 2 indicates volume depletion. High preload (C) would show elevated CVP. Transducer error (D) should be ruled out but the clinical picture supports hypovolaemia. Clinical Takeaway: CVP is one part of hemodynamic assessment — integrate with MAP, urine output, lactate, and clinical perfusion signs. Exam Pearl: Surviving Sepsis Campaign recommends CVP 8–12 mmHg as one target during initial sepsis resuscitation, though dynamic measures are now preferred.","CAN"),
  q("RN-CAT","Critical Care",4,"A client in the ICU develops a temperature of 33.5°C following prolonged surgery. The nurse recognises that inadvertent hypothermia increases the risk of:","Improved wound healing|Coagulopathy, wound infection, and cardiac arrhythmias|Hyperglycaemia only|No significant clinical effects".split("|"),1,"Correct: Perioperative hypothermia (< 36°C) impairs platelet function (coagulopathy), reduces immune function (increased surgical site infection), causes cardiac arrhythmias, prolongs drug metabolism, and increases hospital stay. Incorrect: Hypothermia impairs wound healing (A), not improves it. It causes multiple effects beyond hyperglycaemia (C). It has significant clinical effects (D). Clinical Takeaway: Active rewarming with forced-air warming blankets is the most effective intervention. Maintain normothermia intraoperatively with warmed IV fluids and ambient temperature control. Exam Pearl: For every 1°C drop in core temperature, the risk of surgical wound infection increases by approximately 2–3 times.","CAN"),

  // Emergency Nursing (CAN)
  q("RN-CAT","Emergency Nursing",3,"A client arrives at the emergency department after a motor vehicle collision. Using the Canadian Triage and Acuity Scale (CTAS), a Level 1 designation indicates:","Non-urgent|Resuscitation — conditions requiring immediate life-saving intervention|Semi-urgent|Urgent".split("|"),1,"Correct: CTAS Level 1 (Resuscitation) indicates conditions requiring immediate intervention to prevent death or major morbidity (cardiac arrest, major trauma, respiratory failure). Incorrect: Non-urgent (A) is CTAS Level 5. Semi-urgent (C) is CTAS Level 4. Urgent (D) is CTAS Level 3. Clinical Takeaway: CTAS is used across Canadian emergency departments: Level 1 (Resuscitation), Level 2 (Emergent), Level 3 (Urgent), Level 4 (Less Urgent), Level 5 (Non-Urgent). Exam Pearl: CTAS differs from the US Emergency Severity Index (ESI) — know the Canadian system for the RN-CAT exam.","CAN"),
  q("RN-CAT","Emergency Nursing",2,"A client in the emergency department presents with a Glasgow Coma Scale score of 7. The nurse should:","Discharge the client with follow-up instructions|Ensure airway protection and prepare for possible intubation as GCS ≤ 8 indicates coma|Administer oral medications for headache|Allow the client to sleep and reassess in 2 hours".split("|"),1,"Correct: GCS ≤ 8 indicates severe brain injury and coma. The client cannot protect their own airway and requires intubation for airway management. Incorrect: Discharge (A) is inappropriate for coma. Oral medications (C) are unsafe in a client who cannot protect their airway. Allowing sleep without intervention (D) is dangerous. Clinical Takeaway: GCS components: Eye opening (1–4), Verbal (1–5), Motor (1–6). Minimum score is 3. Serial GCS assessments track neurological status changes. Exam Pearl: 'GCS 8, intubate' is a critical threshold — clients with GCS ≤ 8 require definitive airway management.","CAN"),

  // Pain Management (CAN)
  q("RN-CAT","Pain Management",2,"A client reports pain at a level of 8/10. The nurse notes the client is smiling and talking on the phone. The nurse should:","Assume the client is exaggerating and document pain as 2/10|Accept the client's self-report as the most reliable indicator of pain|Withhold pain medication until the client appears to be in pain|Ask the family to verify the client's pain level".split("|"),1,"Correct: The client's self-report is the gold standard for pain assessment. Behavioural cues do not reliably correlate with pain intensity — clients may use distraction as a coping mechanism. Incorrect: Assuming exaggeration (A) is judgmental and unethical. Withholding medication (C) denies pain relief based on bias. Family verification (D) undermines client autonomy. Clinical Takeaway: Pain is whatever the client says it is (McCaffery definition). Cultural factors, coping mechanisms, and pain tolerance vary widely. Exam Pearl: Undertreated pain is an ethical concern and can lead to chronic pain syndrome, delayed healing, and psychological distress.","CAN"),
  q("RN-CAT","Pain Management",3,"A nurse is caring for a client receiving a patient-controlled analgesia (PCA) pump with morphine. Which assessment finding requires immediate action?","Respiratory rate of 8 breaths per minute|Pain rating of 4/10|Mild drowsiness after medication administration|Itching at the IV site".split("|"),0,"Correct: Respiratory rate < 10 breaths/min is a sign of opioid-induced respiratory depression and requires immediate intervention: stop PCA, stimulate the client, administer naloxone if prescribed, and notify the prescriber. Incorrect: Pain of 4/10 (B) may be acceptable depending on the client's goal. Mild drowsiness (C) is a common expected side effect. Itching (D) is a common opioid side effect managed with antihistamines. Clinical Takeaway: Monitor sedation level using a standardised scale (e.g., Pasero Opioid Sedation Scale) — increasing sedation precedes respiratory depression. Exam Pearl: PCA lockout intervals prevent overdose. Only the client should press the PCA button — never allow family members or staff to press it (PCA by proxy is dangerous).","CAN"),

  // Wound Care (CAN)
  q("RN-CAT","Wound Care",2,"A nurse is selecting a dressing for a wound with moderate exudate and a clean, granulating wound bed. The most appropriate dressing is:","Dry gauze changed every 2 hours|Foam dressing to absorb exudate while maintaining a moist wound environment|Adherent transparent film dressing|Wet-to-dry gauze dressing".split("|"),1,"Correct: Foam dressings absorb moderate exudate, maintain a moist wound healing environment, and provide cushioning. They are changed every 3–7 days depending on exudate amount. Incorrect: Dry gauze (A) does not maintain moisture and disrupts granulation tissue on removal. Transparent film (C) does not absorb exudate. Wet-to-dry dressings (D) cause non-selective debridement and tissue damage — they are no longer recommended as standard practice. Clinical Takeaway: Moist wound healing is the evidence-based standard — select dressings based on wound characteristics (exudate amount, depth, tissue type). Exam Pearl: The TIMERS framework guides wound assessment: Tissue, Infection/Inflammation, Moisture, Edge, Repair/Regeneration, Social factors.","CAN"),

  // Medication Administration (CAN)
  q("RN-CAT","Medication Administration",2,"Before administering any medication, the nurse must verify the:","Five rights: right client, right drug, right dose, right route, right time|Three rights: right drug, right dose, right client|Two rights: right drug and right client|Seven rights including right documentation and right reason".split("|"),3,"Correct: Current best practice recognises at least seven rights of medication administration: right client, right drug, right dose, right route, right time, right documentation, and right reason (indication). Some sources include right response, right to refuse, and right education. Incorrect: Five rights (A) is the traditional minimum but current practice expands beyond five. Three rights (B) and two rights (C) are insufficient. Clinical Takeaway: Always use two client identifiers (name and date of birth or hospital number), check medication three times, and document immediately after administration. Exam Pearl: High-alert medications (insulin, heparin, opioids, potassium, chemotherapy) require independent double checks by two registered nurses.","CAN"),
  q("RN-CAT","Medication Administration",3,"A nurse discovers a medication error after administering the wrong dose to a client. The first action is:","Complete an incident report before assessing the client|Assess the client for adverse effects and implement appropriate interventions|Notify the nurse manager before checking on the client|Document the correct dose in the client's chart and do not report it".split("|"),1,"Correct: Client safety is the immediate priority — assess for adverse effects and intervene as needed. Then notify the prescriber, complete an incident/occurrence report, and document appropriately. Incorrect: Incident report before assessment (A) delays client care. Notifying the manager first (C) delays client assessment. Concealing the error (D) is unethical and potentially illegal. Clinical Takeaway: Medication errors should be reported through the organisation's safety reporting system. A just culture approach focuses on system improvement, not individual blame. Exam Pearl: In Canada, medication incident reporting contributes to the Canadian Medication Incident Reporting and Prevention System (CMIRPS) for national safety improvements.","CAN"),

  // Patient Safety (CAN)
  q("RN-CAT","Patient Safety",2,"A nurse identifies a client as a fall risk during admission. Which intervention is most appropriate?","Place the client in a room closest to the nursing station with the call bell within reach|Apply bilateral wrist restraints|Administer a sedative at night to prevent wandering|Keep all four side rails raised at all times".split("|"),0,"Correct: Room placement near the nursing station increases visibility and response time. Ensuring the call bell is within reach empowers the client to ask for help. Incorrect: Wrist restraints (B) are a last resort and increase agitation and injury risk. Sedatives (C) increase fall risk. All four side rails raised (D) are considered a form of restraint and clients may climb over them, increasing injury risk. Clinical Takeaway: Evidence-based fall prevention includes medication review, toileting schedules, non-slip footwear, clear pathways, adequate lighting, and exercise programs. Exam Pearl: In Canadian facilities, Accreditation Canada's Required Organizational Practices include fall prevention programs with individualised assessments.","CAN"),

  // Delegation/Prioritization (CAN)
  q("RN-CAT","Delegation/Prioritization",3,"A nurse is assigned four clients. Which client should be assessed first?","A client with a blood glucose of 12 mmol/L before lunch|A client reporting sudden onset of chest pain and diaphoresis|A client requesting pain medication for a headache rated 5/10|A client due for discharge teaching".split("|"),1,"Correct: Sudden onset chest pain with diaphoresis suggests acute coronary syndrome — a potentially life-threatening emergency requiring immediate assessment and intervention. Incorrect: Blood glucose of 12 mmol/L (A) is elevated but not immediately life-threatening. Pain medication request (C) is important but not emergent. Discharge teaching (D) can wait. Clinical Takeaway: Use the ABCs (Airway, Breathing, Circulation) and Maslow's hierarchy to prioritise — physiological needs and life-threatening conditions come first. Exam Pearl: On the RN-CAT exam, prioritisation questions test the ability to identify which client needs attention FIRST based on clinical urgency.","CAN"),
  q("RN-CAT","Delegation/Prioritization",3,"An RN is working with a Licensed Practical Nurse (LPN) and a UCP on a medical unit. Which assignment is most appropriate for the LPN?","Admitting a new client and completing the initial nursing assessment|Administering oral medications to stable clients with predictable outcomes|Performing tracheal suctioning on a ventilator-dependent client|Developing the nursing care plan for a complex postoperative client".split("|"),1,"Correct: LPNs (RPNs in Ontario) can administer medications to stable clients with predictable outcomes within their scope of practice and competence. Incorrect: Initial nursing assessment (A) and care plan development (D) for complex clients are RN responsibilities. Tracheal suctioning on ventilator clients (C) may be beyond the LPN scope depending on provincial regulations and client stability. Clinical Takeaway: In Canada, LPN scope varies by province — always verify provincial regulatory body guidelines. The RN retains accountability for overall client care when delegating. Exam Pearl: The key phrase is 'stable with predictable outcomes' — this defines the appropriate LPN client assignment.","CAN"),

  // Leadership/Collaboration (CAN)
  q("RN-CAT","Leadership/Collaboration",3,"During an interprofessional team meeting, a disagreement arises about a client's plan of care. The nurse should:","Defer to the physician's opinion without discussion|Advocate for the client's best interests using evidence-based rationale while respecting team members' expertise|Leave the meeting to avoid conflict|Agree with the majority opinion regardless of evidence".split("|"),1,"Correct: Nurses are client advocates and should contribute evidence-based perspectives respectfully within interprofessional teams. Effective collaboration involves assertive communication, mutual respect, and shared decision-making focused on client outcomes. Incorrect: Deferring without discussion (A) does not fulfil the advocacy role. Leaving (C) avoids professional responsibility. Agreeing without evidence (D) compromises client safety. Clinical Takeaway: The Canadian Interprofessional Health Collaborative (CIHC) competencies include communication, collaboration, role clarification, conflict resolution, and client-centred practice. Exam Pearl: SBAR (Situation, Background, Assessment, Recommendation) is the recommended communication framework for interprofessional handoffs and discussions.","CAN"),

  // Ethical/Legal Practice (CAN)
  q("RN-CAT","Ethical/Legal Practice",3,"A nurse discovers that a colleague has been diverting narcotics. The nurse's professional obligation is to:","Confront the colleague privately and give them a chance to stop|Report the concern to the nurse manager or appropriate authority immediately|Ignore the situation to maintain workplace relationships|Wait to see if the problem resolves on its own".split("|"),1,"Correct: Nurses have a professional and legal duty to report suspected narcotic diversion to protect clients and maintain professional standards. Reporting to the manager initiates investigation and appropriate action. Incorrect: Private confrontation (A) may compromise evidence and does not fulfil the duty to report. Ignoring (C) and waiting (D) put clients at risk and violate professional obligations. Clinical Takeaway: Provincial regulatory bodies require nurses to report unsafe practice. The nurse is protected from reprisal when reporting in good faith. Exam Pearl: Narcotic diversion is a criminal offense under the Controlled Drugs and Substances Act in Canada and also triggers regulatory investigation by the nursing college.","CAN"),
  q("RN-CAT","Ethical/Legal Practice",4,"A client with a terminal illness asks the nurse about Medical Assistance in Dying (MAiD) in Canada. The nurse should:","Refuse to discuss it as it conflicts with the nurse's personal beliefs|Provide accurate information about MAiD eligibility criteria and refer the client to the appropriate resources|Immediately arrange for MAiD without further assessment|Tell the client that MAiD is illegal in Canada".split("|"),1,"Correct: Regardless of personal beliefs, the nurse has a duty to provide accurate information. MAiD is legal in Canada under specific criteria (grievous and irremediable medical condition causing enduring suffering). The nurse should provide information and facilitate referral to appropriate services. Incorrect: Refusing to discuss (A) fails the duty to inform. The nurse does not arrange MAiD (C) — it requires a formal process with multiple assessments. MAiD is legal (D) since June 2016 in Canada. Clinical Takeaway: MAiD eligibility requires: eligible for health services in Canada, 18+ years, capable of making health decisions, grievous and irremediable condition, and voluntary request. Conscientious objection is protected but requires effective referral. Exam Pearl: The Criminal Code of Canada outlines MAiD provisions. Two independent medical practitioners must assess eligibility, and a 90-day assessment period applies for Track 2 (death not reasonably foreseeable).","CAN"),

  // Additional CAN topics to reach 75
  // Cardiovascular (CAN)
  q("RN-CAT","Cardiovascular",4,"A client with a permanent pacemaker develops hiccups and intercostal muscle twitching. The nurse suspects:","Normal pacemaker function|Pacemaker lead displacement causing diaphragmatic pacing|Battery depletion|Electromagnetic interference".split("|"),1,"Correct: Diaphragmatic or intercostal muscle stimulation from a displaced pacemaker lead causes hiccups and muscle twitching. The lead has migrated and is stimulating nearby muscles instead of cardiac tissue. Incorrect: This is not normal function (A). Battery depletion (C) causes rate changes, not muscle stimulation. EMI (D) causes sensing issues, not muscular symptoms. Clinical Takeaway: Obtain a stat chest X-ray to assess lead position and interrogate the pacemaker device to evaluate lead impedance and capture thresholds. Exam Pearl: Other signs of lead displacement include failure to capture (no QRS after pacemaker spike) or failure to sense (inappropriate pacing over native rhythm).","CAN"),

  // Respiratory (CAN)
  q("RN-CAT","Respiratory",4,"A client with a chest tube has continuous bubbling in the water-seal chamber. The nurse should:","Clamp the chest tube immediately|Assess for an air leak by systematically clamping the tubing from the client toward the collection system|Increase wall suction to stop the bubbling|Remove the chest tube as it is malfunctioning".split("|"),1,"Correct: Continuous bubbling in the water-seal chamber indicates an air leak. Systematic clamping from the client-end toward the drainage system helps locate the leak source — if bubbling stops when clamping near the client, the leak is at the insertion site or within the lung. Incorrect: Clamping the tube (A) can cause tension pneumothorax and should only be done briefly for assessment. Increasing suction (C) does not resolve an air leak. Removing the tube (D) could cause pneumothorax. Clinical Takeaway: Intermittent bubbling with expiration or coughing is normal and indicates air evacuation. Continuous bubbling is abnormal. Exam Pearl: Tidaling (water level rise and fall with respirations) in the water-seal chamber is normal and indicates tube patency — absent tidaling may mean the tube is occluded or the lung is re-expanded.","CAN"),

  // Pharmacology (CAN)
  q("RN-CAT","Pharmacology",2,"A client asks the nurse about the purpose of taking a proton pump inhibitor (pantoprazole) before breakfast. The nurse explains:","It works best when taken at bedtime|Taking it 30 minutes before the first meal of the day maximises acid suppression because it targets active proton pumps|It should be taken with a high-fat meal|The timing does not matter".split("|"),1,"Correct: PPIs irreversibly inhibit the H⁺/K⁺ ATPase proton pump. They are most effective when taken 30 minutes before a meal because eating stimulates the proton pumps, making them accessible to the drug. Incorrect: Bedtime (A) is less effective. High-fat meals (C) are not required. Timing matters significantly for efficacy (D). Clinical Takeaway: Long-term PPI use is associated with increased risk of C. difficile infection, bone fractures, vitamin B12 deficiency, and hypomagnesaemia. Exam Pearl: PPIs end in '-prazole' (omeprazole, pantoprazole, esomeprazole). H2 blockers end in '-tidine' (ranitidine, famotidine).","CAN"),

  // GI (CAN)
  q("RN-CAT","Gastrointestinal",4,"A client with cirrhosis has a paracentesis removing 5 litres of ascitic fluid. The nurse should anticipate:","No additional intervention needed|IV albumin infusion to prevent post-paracentesis circulatory dysfunction|Strict fluid restriction for 48 hours without albumin|Immediate diuretic therapy".split("|"),1,"Correct: Large-volume paracentesis (> 5 L) causes intravascular volume shifts that can lead to circulatory dysfunction and renal impairment. IV albumin (6–8 g per litre removed) prevents this complication. Incorrect: No intervention (A) risks hemodynamic instability. Fluid restriction alone (C) does not prevent circulatory dysfunction. Diuretics (D) would worsen hypovolaemia. Clinical Takeaway: Monitor vital signs, weight, and abdominal girth post-procedure. Watch for signs of peritonitis (fever, abdominal pain) which can complicate the procedure. Exam Pearl: Spontaneous bacterial peritonitis (SBP) is diagnosed by ascitic fluid PMN count ≥ 250 cells/mm³ and treated with ceftriaxone or cefotaxime.","CAN"),

  // Neurological (CAN)
  q("RN-CAT","Neurological",2,"A client taking phenytoin for seizure management should have which laboratory value monitored regularly?","Serum potassium|Serum phenytoin level (therapeutic range 40–80 μmol/L)|Serum sodium|Serum calcium only".split("|"),1,"Correct: Phenytoin has a narrow therapeutic index. In Canada, the therapeutic range is 40–80 μmol/L (or 10–20 μg/mL in US units). Levels above therapeutic range cause toxicity (nystagmus, ataxia, lethargy). Incorrect: Potassium (A) and sodium (C) are not directly affected by phenytoin. While calcium monitoring may be needed long-term (D), serum drug levels are the priority monitoring. Clinical Takeaway: Signs of phenytoin toxicity in order of increasing levels: nystagmus → ataxia → slurred speech → lethargy → seizures (paradoxical). Exam Pearl: Phenytoin exhibits zero-order kinetics — small dose increases can cause disproportionately large level increases. Always hold the dose and report toxic levels.","CAN"),

  // Mental Health (CAN)
  q("RN-CAT","Mental Health",2,"A nurse is planning care for a client with major depressive disorder. Which assessment is the highest priority at admission?","Sleep pattern assessment|Suicide risk assessment|Nutritional status assessment|Social support assessment".split("|"),1,"Correct: Suicide risk assessment is the highest priority for any client with depression. It includes asking directly about suicidal ideation, plan, means, and intent. Safety is always the first concern. Incorrect: Sleep (A), nutrition (C), and social support (D) are all important but secondary to safety. A complete assessment includes all of these, but suicide risk is assessed first. Clinical Takeaway: Use validated tools such as the Columbia Suicide Severity Rating Scale (C-SSRS). Asking about suicide does not increase the risk — it opens the door to intervention. Exam Pearl: Risk factors for suicide include previous attempt, mental illness, substance use, social isolation, chronic pain, access to lethal means, and recent loss.","CAN"),

  // Pediatrics (CAN)
  q("RN-CAT","Pediatrics",4,"A 3-year-old child is admitted with suspected intussusception. The nurse expects to find:","Painless rectal bleeding|Episodic severe abdominal pain, 'currant jelly' stools, and a palpable sausage-shaped mass in the RUQ|Projectile vomiting immediately after feeding|Ribbon-like stools".split("|"),1,"Correct: Intussusception (telescoping of bowel) presents with intermittent severe colicky pain (child draws knees to chest and screams), 'currant jelly' stools (blood and mucus), palpable sausage-shaped mass, and vomiting. Incorrect: Painless bleeding (A) suggests Meckel diverticulum. Projectile vomiting (C) suggests pyloric stenosis. Ribbon-like stools (D) suggest Hirschsprung disease. Clinical Takeaway: Ultrasound shows a 'target sign' or 'doughnut sign.' Treatment is air or barium enema reduction; surgery if reduction fails or perforation occurs. Exam Pearl: Intussusception is the most common cause of intestinal obstruction in children 6 months to 3 years.","CAN"),

  // Maternity/OB (CAN)
  q("RN-CAT","Maternity/OB",4,"A client at 28 weeks gestation who is Rh-negative with an Rh-positive partner should receive:","No treatment until after delivery|Rh immune globulin (RhoGAM/WinRho) at 28 weeks gestation and within 72 hours postpartum if the newborn is Rh-positive|Rh immune globulin only after delivery|Anti-D antibiotics".split("|"),1,"Correct: Rh immune globulin prevents Rh sensitisation by destroying any fetal Rh-positive red blood cells in the maternal circulation before the immune system can respond. It is given prophylactically at 28 weeks and postpartum within 72 hours. Incorrect: Waiting until delivery (A, C) risks sensitisation during pregnancy. Anti-D antibiotics (D) is not a real treatment — Rh is treated with immune globulin. Clinical Takeaway: Additional doses are given after any sensitising event: amniocentesis, chorionic villus sampling, trauma, or vaginal bleeding. Exam Pearl: In Canada, the product is marketed as WinRho. An indirect Coombs test (antibody screen) should be negative before administration — a positive result means sensitisation has already occurred.","CAN"),

  // Wound Care (CAN)
  q("RN-CAT","Wound Care",3,"A client has a pressure injury with 50% yellow slough covering the wound bed. The nurse should plan for:","Leaving the slough intact as it protects the wound|Autolytic debridement using a moisture-retentive dressing to soften and remove the slough|Surgical debridement for all wounds with slough|Application of a dry dressing to desiccate the slough".split("|"),1,"Correct: Autolytic debridement uses the body's own enzymes under a moisture-retentive dressing (hydrogel, hydrocolloid) to liquefy and separate devitalized tissue. It is selective, painless, and appropriate for non-infected wounds. Incorrect: Leaving slough (A) impedes healing. Surgical debridement (C) is reserved for extensive necrosis or infection. Dry dressings (D) impair moist wound healing. Clinical Takeaway: Wound bed preparation follows the TIME framework (Tissue, Infection, Moisture, Edge) — removing non-viable tissue is the first step. Exam Pearl: Types of debridement: autolytic (moisture dressings), enzymatic (collagenase), mechanical (wet-to-dry — now discouraged), sharp/surgical (scalpel by trained provider), and biological (medical-grade maggots).","CAN"),

  // Patient Safety (CAN)
  q("RN-CAT","Patient Safety",3,"A nurse receives a telephone order from a prescriber. To enhance patient safety, the nurse should:","Implement the order without verification|Read back the complete order to the prescriber for verification|Write the order down and implement it without repeating it back|Ask another nurse to take the order instead".split("|"),1,"Correct: The read-back process (write down, read back, receive confirmation) reduces communication errors in verbal and telephone orders. This is a patient safety standard across Canadian healthcare organisations. Incorrect: Implementing without verification (A) risks errors. No read-back (C) misses an important safety step. Avoiding telephone orders entirely (D) is impractical. Clinical Takeaway: Verbal orders should be limited to urgent situations. The order must be authenticated (cosigned) by the prescriber within the timeframe specified by organizational policy (usually 24 hours). Exam Pearl: Accreditation Canada's Required Organizational Practices include verbal order read-back as a communication safety practice.","CAN"),

  // Leadership/Collaboration (CAN)
  q("RN-CAT","Leadership/Collaboration",2,"A nurse is using SBAR to communicate a client status change to the prescriber. The 'A' in SBAR stands for:","Action taken so far|Assessment — the nurse's clinical assessment of the situation|Allergy information|Admission diagnosis".split("|"),1,"Correct: SBAR: Situation (what is happening), Background (relevant history), Assessment (the nurse's clinical assessment and interpretation), Recommendation (what the nurse suggests or requests). Incorrect: Action taken (A) may be included but is not what A stands for. Allergies (C) may be in Background. Admission diagnosis (D) is part of Background. Clinical Takeaway: SBAR promotes structured, concise communication that reduces ambiguity and improves patient safety during handoffs and escalation. Exam Pearl: Example: 'S: Mrs. Smith's BP is 80/50. B: She is post-op day 1 from hip replacement, on IV fluids. A: I believe she is hypovolaemic. R: I recommend a fluid bolus and assessment by the physician.'","CAN"),

  // Ethical/Legal Practice (CAN)
  q("RN-CAT","Ethical/Legal Practice",3,"A competent client with end-stage renal disease refuses haemodialysis despite understanding the consequences. The nurse should:","Continue dialysis against the client's wishes as it is life-saving|Respect the client's informed decision, document it, and ensure palliative support is offered|Contact the client's family to override the decision|Seek a court order to force treatment".split("|"),1,"Correct: Competent adults have the right to refuse any treatment, including life-sustaining treatment, when they are fully informed of the consequences. The nurse documents the refusal, ensures the decision is informed, and facilitates access to palliative care. Incorrect: Continuing treatment without consent (A) is battery. Family cannot override a competent adult's decision (C). Court orders (D) are not appropriate when the client is competent. Clinical Takeaway: The Canadian Nurses Association Code of Ethics emphasises that nurses uphold the client's right to informed consent and self-determination. Exam Pearl: Key elements of informed consent: disclosure of information, client understanding, voluntariness, competence/capacity, and decision.","CAN"),

  // ============================================================
  // USA RN QUESTIONS (75) — exam: NCLEX-RN, region_scope: US
  // ============================================================

  // Fundamentals (USA)
  q("NCLEX-RN","Fundamentals",2,"A nurse is caring for a client who fell at home and was admitted with a hip fracture. Which nursing diagnosis takes priority?","Impaired physical mobility|Acute pain|Risk for impaired skin integrity|Deficient knowledge".split("|"),1,"Correct: Acute pain is the priority nursing diagnosis based on Maslow's hierarchy — physiological needs (including pain relief) take precedence. Pain control also facilitates mobility, skin integrity, and learning. Incorrect: Impaired mobility (A) is important but secondary to pain. Skin integrity (C) and knowledge (D) are lower priority than acute pain. Clinical Takeaway: Prioritize using Maslow's hierarchy: physiological needs > safety > love/belonging > esteem > self-actualization. Exam Pearl: On NCLEX, when multiple nursing diagnoses are listed, identify which addresses an actual (vs. risk) physiological need.","US"),
  q("NCLEX-RN","Fundamentals",2,"A nurse is preparing to administer an intramuscular injection to an adult client. The preferred site for most IM injections is the:","Dorsogluteal muscle|Ventrogluteal muscle|Deltoid muscle|Vastus lateralis muscle".split("|"),1,"Correct: The ventrogluteal site is the preferred IM injection site for adults because it has the greatest muscle thickness, is free of major nerves and blood vessels, and has a well-defined anatomical landmark (anterior superior iliac spine). Incorrect: Dorsogluteal (A) is no longer recommended due to risk of sciatic nerve injury. Deltoid (C) is used for small volumes only (≤ 1 mL). Vastus lateralis (D) is preferred for infants but not the first choice in adults. Clinical Takeaway: Landmark for ventrogluteal: place palm on greater trochanter, index finger on ASIS, spread middle finger toward iliac crest. Exam Pearl: The Z-track technique is used for IM injections that may stain tissue (iron dextran) or to prevent medication leakage.","US"),
  q("NCLEX-RN","Fundamentals",3,"A nurse is caring for a client who is NPO after midnight for a scheduled surgery. The client asks for breakfast the next morning. The nurse should:","Allow the client to eat a light breakfast|Explain the reason for NPO status and reinforce that eating could cause aspiration during anesthesia|Give the client ice chips as a compromise|Delay the surgery to allow the client to eat".split("|"),1,"Correct: NPO status before surgery prevents aspiration of gastric contents during anesthesia. The nurse should explain the rationale clearly and offer mouth care for comfort. Incorrect: Allowing food (A) increases aspiration risk and would cancel the surgery. Ice chips (C) may be ordered by the provider but the nurse should not independently allow them. Delaying surgery (D) is not within the nurse's authority and is not appropriate. Clinical Takeaway: Current ASA guidelines allow clear liquids up to 2 hours before surgery and light meals up to 6 hours before, but institutional protocols must be followed. Exam Pearl: Aspiration of gastric contents during anesthesia (Mendelson syndrome) can cause aspiration pneumonitis, a life-threatening condition.","US"),

  // Advanced Assessment (USA)
  q("NCLEX-RN","Advanced Assessment",3,"During a cardiovascular assessment, the nurse notes an S3 heart sound in a 65-year-old client. This finding is:","Normal in older adults|Pathological and often associated with heart failure|Always benign|Indicative of aortic stenosis".split("|"),1,"Correct: An S3 heart sound (ventricular gallop) in adults over 40 is pathological and indicates volume overload or ventricular dysfunction, commonly seen in heart failure. It is heard best at the apex with the bell of the stethoscope. Incorrect: S3 is normal in children and young adults (A) but pathological in older adults. It is not always benign in adults (C). Aortic stenosis (D) produces a systolic crescendo-decrescendo murmur. Clinical Takeaway: S3 = 'Ken-TUC-ky' cadence. S4 = 'TEN-nes-see' cadence. S4 indicates a stiff, noncompliant ventricle (hypertension, hypertrophic cardiomyopathy). Exam Pearl: Both S3 and S4 are low-pitched sounds best heard with the bell of the stethoscope at the apex in the left lateral decubitus position.","US"),

  // Pharmacology (USA)
  q("NCLEX-RN","Pharmacology",2,"A client is prescribed atorvastatin (Lipitor) for hyperlipidemia. The nurse should instruct the client to report:","Increased appetite|Unexplained muscle pain, tenderness, or weakness|Mild headache|Increased urination".split("|"),1,"Correct: Unexplained muscle symptoms may indicate rhabdomyolysis, a rare but serious adverse effect of statins. CK levels should be checked if symptoms develop. Incorrect: Increased appetite (A) is not a statin side effect. Mild headache (C) is not a concerning statin side effect. Increased urination (D) is not associated with statin use. Clinical Takeaway: Statins are hepatotoxic — monitor liver function tests. Take statins in the evening (when cholesterol synthesis peaks) unless using atorvastatin or rosuvastatin (long half-lives, can be taken anytime). Exam Pearl: Avoid grapefruit juice with most statins (inhibits CYP3A4, increasing drug levels and toxicity risk).","US"),
  q("NCLEX-RN","Pharmacology",3,"A nurse is administering IV potassium chloride to a client with hypokalemia. Which action is essential?","Administer potassium by IV push for rapid correction|Use an infusion pump and do not exceed 10–20 mEq/hour with cardiac monitoring|Mix potassium in a D5W bag without monitoring|Administer potassium intramuscularly".split("|"),1,"Correct: IV potassium must never be given by push (causes fatal cardiac arrest). It must be diluted, administered via infusion pump at ≤ 10–20 mEq/hour, with continuous cardiac monitoring for arrhythmias. Incorrect: IV push (A) is fatal. Without monitoring (C) is unsafe. IM potassium (D) is not an approved route. Clinical Takeaway: Normal serum potassium: 3.5–5.0 mEq/L. Hypokalemia signs include muscle weakness, leg cramps, flattened T waves, and U waves on ECG. Exam Pearl: Potassium is a high-alert medication requiring independent double verification before administration.","US"),
  q("NCLEX-RN","Pharmacology",4,"A client receiving an aminoglycoside antibiotic reports tinnitus and dizziness. The nurse should:","Continue the medication and monitor|Hold the medication and notify the provider as these are signs of ototoxicity|Administer an antiemetic for the dizziness|Decrease the infusion rate".split("|"),1,"Correct: Tinnitus and dizziness are signs of ototoxicity (vestibular and cochlear damage), a serious adverse effect of aminoglycosides (gentamicin, tobramycin). The medication should be held and the provider notified immediately. Incorrect: Continuing (A) risks permanent hearing loss. An antiemetic (C) treats symptoms but not the cause. Decreasing the rate (D) does not address the toxicity. Clinical Takeaway: Aminoglycosides are also nephrotoxic — monitor BUN, creatinine, trough levels. Peak and trough levels guide dose adjustments. Exam Pearl: Ototoxicity from aminoglycosides may be irreversible. Risk increases with concurrent use of loop diuretics (furosemide).","US"),

  // Cardiovascular (USA)
  q("NCLEX-RN","Cardiovascular",3,"A client with newly diagnosed atrial fibrillation asks why they need an anticoagulant. The nurse explains:","Anticoagulants convert the heart rhythm back to normal|Atrial fibrillation causes stagnant blood flow in the atria, increasing the risk of clot formation and stroke|Anticoagulants strengthen the heart muscle|Anticoagulants are only needed for ventricular arrhythmias".split("|"),1,"Correct: In atrial fibrillation, ineffective atrial contraction leads to blood stasis in the atria, particularly the left atrial appendage, creating a high risk for thrombus formation and subsequent embolic stroke. Anticoagulants prevent clot formation. Incorrect: Anticoagulants do not convert rhythm (A) — antiarrhythmics or cardioversion do that. They don't strengthen heart muscle (C). A-fib specifically increases stroke risk (D). Clinical Takeaway: CHA₂DS₂-VASc score determines stroke risk and anticoagulation need. DOACs (apixaban, rivaroxaban) are preferred over warfarin for non-valvular AF. Exam Pearl: Atrial fibrillation is the most common sustained cardiac arrhythmia and the leading cardiac cause of ischemic stroke.","US"),
  q("NCLEX-RN","Cardiovascular",2,"A nurse is caring for a client with heart failure who is prescribed a daily weight. The nurse instructs the client to weigh themselves:","At different times throughout the day|Every morning at the same time, after voiding, in similar clothing|Only when they feel bloated|Once per week on the same day".split("|"),1,"Correct: Daily weight at the same time, after voiding, in similar clothing provides the most accurate assessment of fluid balance. A gain of > 2 lbs (0.9 kg) overnight or > 5 lbs (2.3 kg) in a week should be reported. Incorrect: Different times (A) provides inconsistent data. Only when bloated (C) misses early fluid retention. Weekly (D) may miss rapid fluid changes. Clinical Takeaway: 1 liter of fluid = approximately 1 kg (2.2 lbs) of weight. Daily weights are the most reliable indicator of fluid status changes. Exam Pearl: Teach clients to report rapid weight gain to their provider — it may indicate decompensation requiring diuretic adjustment.","US"),

  // Respiratory (USA)
  q("NCLEX-RN","Respiratory",3,"A client with a pulse oximetry reading of 88% on room air has COPD. The nurse should:","Apply oxygen at 6 L/min via simple mask|Titrate oxygen to maintain SpO₂ between 88–92% using a low-flow device|Withhold oxygen as the client is used to low levels|Apply 100% non-rebreather mask immediately".split("|"),1,"Correct: COPD clients with chronic CO₂ retention should receive controlled oxygen therapy targeting SpO₂ of 88–92%. High-flow oxygen can suppress hypoxic respiratory drive, leading to hypoventilation and CO₂ narcosis. Incorrect: 6 L/min (A) may be too much. Withholding oxygen (C) is dangerous when SpO₂ is below target. Non-rebreather (D) delivers too high FiO₂ for COPD patients. Clinical Takeaway: Use a Venturi mask for precise FiO₂ delivery in COPD patients. Nasal cannula at 1–2 L/min is also appropriate. Exam Pearl: Not all COPD patients are CO₂ retainers — but for the NCLEX, assume low-flow oxygen for COPD unless told otherwise.","US"),
  q("NCLEX-RN","Respiratory",2,"A client is being discharged with a rescue inhaler (albuterol). The nurse teaches that this medication is used:","On a regular schedule every 6 hours|As needed for acute bronchospasm and shortness of breath|As a replacement for controller medications|Only at bedtime".split("|"),1,"Correct: Albuterol is a short-acting beta-2 agonist (SABA) used as a rescue medication for acute bronchospasm. Onset is 5–15 minutes. It provides rapid symptom relief but does not treat underlying inflammation. Incorrect: Regular scheduling (A) is for controller medications, not rescue inhalers. It does not replace controllers (C). It is used as needed (D), not only at bedtime. Clinical Takeaway: Needing a rescue inhaler > 2 times/week suggests poorly controlled asthma and the need for a controller medication (inhaled corticosteroid). Exam Pearl: Side effects of albuterol include tremors, tachycardia, and hypokalemia from beta-2 stimulation.","US"),

  // Renal (USA)
  q("NCLEX-RN","Renal",3,"A client with end-stage renal disease is on a fluid restriction of 1,500 mL/day. The nurse should teach the client to:","Drink freely and the dialysis machine will remove the excess fluid|Track all fluid intake including ice chips, gelatin, and soup, and spread intake throughout the day|Only count water as fluid intake|Drink all fluids in the morning to feel better".split("|"),1,"Correct: Fluid restriction includes all fluids and foods that are liquid at room temperature: water, juice, coffee, ice chips, gelatin, popsicles, soup, and ice cream. Spreading intake across the day prevents excessive thirst. Incorrect: Relying on dialysis (A) leads to fluid overload complications between sessions. Only counting water (C) underestimates total intake. Drinking all fluids in the morning (D) leads to prolonged thirst for the rest of the day. Clinical Takeaway: Tips to manage thirst: hard candy, frozen grapes, swishing mouthwash, chewing gum, and using small cups. Exam Pearl: Weight gain between dialysis sessions reflects fluid accumulation — ideal interdialytic weight gain is < 2–3 kg.","US"),

  // Endocrine (USA)
  q("NCLEX-RN","Endocrine",2,"A client newly diagnosed with hypothyroidism asks about expected symptoms before treatment. The nurse explains:","Weight loss, heat intolerance, and tremors|Fatigue, weight gain, cold intolerance, and constipation|Exophthalmos and rapid heart rate|Excessive thirst and urination".split("|"),1,"Correct: Hypothyroidism (decreased thyroid hormone) slows metabolism, causing fatigue, weight gain, cold intolerance, constipation, dry skin, bradycardia, and menstrual irregularities. Incorrect: Weight loss and heat intolerance (A) are hyperthyroidism symptoms. Exophthalmos and tachycardia (C) occur in Graves disease (hyperthyroidism). Excessive thirst/urination (D) suggests diabetes. Clinical Takeaway: Hypothyroidism is treated with levothyroxine — start low and titrate slowly, especially in elderly and cardiac patients. Monitor TSH every 6–8 weeks until stable. Exam Pearl: Myxedema coma is the most severe form of hypothyroidism — presents with hypothermia, altered mental status, and respiratory failure. It is a medical emergency.","US"),
  q("NCLEX-RN","Endocrine",3,"A client with diabetic ketoacidosis has a blood glucose of 450 mg/dL, pH 7.18, and positive ketones. The nurse's priority intervention is:","Administer subcutaneous insulin lispro|Initiate IV regular insulin infusion and aggressive IV fluid resuscitation|Give orange juice for the low pH|Administer IV sodium bicarbonate as the first intervention".split("|"),1,"Correct: DKA treatment priorities: IV fluid resuscitation (NS first to correct dehydration and electrolyte imbalances), then continuous IV regular insulin drip, potassium replacement (check K+ before insulin — insulin drives K+ intracellularly), and monitoring. Incorrect: Subcutaneous insulin (A) has unpredictable absorption in dehydrated clients. Orange juice (C) would raise glucose further. Bicarbonate (D) is reserved for pH < 6.9 due to risk of paradoxical CNS acidosis. Clinical Takeaway: Do not give insulin until potassium is confirmed ≥ 3.3 mEq/L. When glucose reaches 200–250 mg/dL, add dextrose to IV fluids to prevent hypoglycemia while continuing insulin to clear ketones. Exam Pearl: DKA predominantly occurs in Type 1 diabetes. HHS occurs in Type 2 — very high glucose (> 600), minimal ketones, high osmolality.","US"),

  // GI (USA)
  q("NCLEX-RN","Gastrointestinal",2,"A client with peptic ulcer disease is prescribed omeprazole. The nurse explains this medication works by:","Neutralizing stomach acid|Inhibiting the proton pump to reduce gastric acid secretion|Forming a protective coating over the ulcer|Killing Helicobacter pylori bacteria".split("|"),1,"Correct: PPIs (omeprazole, pantoprazole, esomeprazole) irreversibly inhibit the H+/K+ ATPase proton pump on parietal cells, reducing gastric acid secretion by up to 90%. Incorrect: Neutralizing acid (A) describes antacids (Tums, Maalox). Protective coating (C) describes sucralfate. Killing H. pylori (D) describes antibiotics used in triple therapy. Clinical Takeaway: PPIs should be taken 30 minutes before the first meal of the day for maximum efficacy. Long-term use requires monitoring for C. diff, osteoporosis, and B12 deficiency. Exam Pearl: Triple therapy for H. pylori: PPI + clarithromycin + amoxicillin (or metronidazole) for 14 days.","US"),
  q("NCLEX-RN","Gastrointestinal",3,"A client with a colostomy in the ascending colon should expect stool consistency to be:","Formed and brown|Liquid to semi-liquid and continuous|Paste-like|Solid pellets".split("|"),1,"Correct: The ascending colon absorbs minimal water, so stool from an ascending colostomy is liquid to semi-liquid. As the colostomy moves distally (transverse, descending, sigmoid), stool becomes progressively more formed. Incorrect: Formed stool (A) is from descending or sigmoid colostomies. Paste-like (C) is from transverse colostomy. Solid pellets (D) are not typical of any colostomy. Clinical Takeaway: Ascending colostomies require frequent pouch emptying and skin protection. Sigmoid colostomies may allow for irrigation and scheduled pouch changes. Exam Pearl: Ileostomies produce liquid, enzyme-rich effluent that is very irritating to skin — meticulous peristomal skin care is essential.","US"),

  // Neurological (USA)
  q("NCLEX-RN","Neurological",3,"A client with a head injury has clear fluid draining from the nose. The nurse tests it with a glucose strip and it is positive. This suggests:","Allergic rhinitis|Cerebrospinal fluid leak (rhinorrhea)|Normal nasal secretions|Sinus infection".split("|"),1,"Correct: CSF contains glucose (unlike nasal mucus). Positive glucose on a test strip or the 'halo sign' (clear ring around blood on linen) indicates CSF leak through a basilar skull fracture. Incorrect: Allergic rhinitis (A) produces glucose-negative mucus. Normal nasal secretions (C) do not contain glucose. Sinus infection (D) produces purulent, glucose-negative drainage. Clinical Takeaway: Do NOT pack the nose or place an NG tube with suspected CSF leak — this increases infection risk. Elevate HOB 30 degrees to reduce CSF pressure. Most leaks seal spontaneously. Exam Pearl: CSF leak increases meningitis risk. Instruct the client not to blow their nose, strain, or cough forcefully.","US"),
  q("NCLEX-RN","Neurological",2,"A client experiencing a seizure is on the floor. The nurse's priority action is:","Insert a padded tongue blade between the teeth|Protect the client's head and clear the area of harmful objects|Restrain the client to prevent injury|Administer oral medication immediately".split("|"),1,"Correct: During a seizure, the priority is safety: protect the head (place something soft underneath), clear surrounding objects, do not restrain or insert anything into the mouth, position on the side after the seizure ends, and time the seizure. Incorrect: Tongue blades (A) can break teeth and cause aspiration. Restraining (C) can cause musculoskeletal injury. Oral medications (D) are a choking risk during a seizure. Clinical Takeaway: After the seizure, maintain airway (recovery position), check for injuries, and document seizure characteristics (type, duration, post-ictal state). Exam Pearl: Call for emergency help if the seizure lasts > 5 minutes (status epilepticus) or if the client does not regain consciousness between seizures.","US"),

  // Musculoskeletal (USA)
  q("NCLEX-RN","Musculoskeletal",3,"A client in a leg cast reports increasing pain unrelieved by analgesics, numbness, and tingling in the toes. The nurse suspects:","Normal post-fracture pain|Compartment syndrome requiring immediate intervention|Deep vein thrombosis|Peripheral neuropathy".split("|"),1,"Correct: The 6 P's of compartment syndrome: Pain (disproportionate, unrelieved by analgesics), Pressure (tense compartment), Paresthesia (numbness/tingling), Pallor, Paralysis, and Pulselessness (late sign). This is a surgical emergency requiring fasciotomy. Incorrect: Normal pain (A) responds to analgesics. DVT (C) presents with calf swelling and warmth. Peripheral neuropathy (D) has a gradual onset. Clinical Takeaway: Compartment pressure > 30 mmHg or within 30 mmHg of diastolic BP requires emergent fasciotomy. Delay causes irreversible muscle and nerve damage within 6 hours. Exam Pearl: Do NOT elevate the limb above the heart in compartment syndrome — this reduces arterial flow further. Keep at heart level.","US"),

  // Hematology (USA)
  q("NCLEX-RN","Hematology",3,"A client with iron deficiency anemia is prescribed oral ferrous sulfate. The nurse should instruct the client to:","Take the iron with milk or antacids for better absorption|Take the iron on an empty stomach with vitamin C (orange juice) to enhance absorption|Crush the enteric-coated tablet for easier swallowing|Expect stools to become lighter in color".split("|"),1,"Correct: Iron is best absorbed on an empty stomach (1 hour before or 2 hours after meals). Vitamin C enhances iron absorption by maintaining iron in the more absorbable ferrous state. Incorrect: Milk, antacids, calcium (A) decrease iron absorption. Enteric-coated tablets (C) should not be crushed. Iron causes dark/black stools (D), not lighter. Clinical Takeaway: Side effects include constipation, nausea, and dark stools. Liquid iron should be taken through a straw to prevent tooth staining. Exam Pearl: Iron is a common cause of pediatric poisoning — always educate about safe storage away from children.","US"),

  // Oncology (USA)
  q("NCLEX-RN","Oncology",3,"A client receiving chemotherapy has a white blood cell count of 1,500/mm³. The nurse should implement:","Standard precautions only|Neutropenic precautions including protective isolation, hand hygiene, and avoiding fresh flowers and raw foods|Contact precautions|Allow visitors without restriction".split("|"),1,"Correct: WBC 1,500/mm³ with likely low ANC indicates neutropenia and high infection risk. Implement neutropenic precautions: private room, strict hand hygiene, no fresh flowers/fruits/raw foods, limit visitors, avoid sick contacts, and monitor temperature closely. Incorrect: Standard precautions alone (A) are insufficient. Contact precautions (C) are for specific pathogens. Unrestricted visitors (D) increase infection exposure. Clinical Takeaway: ANC < 500 = severe neutropenia. Temperature ≥ 100.4°F (38°C) in a neutropenic client is an emergency — obtain blood cultures and start empiric broad-spectrum antibiotics within 1 hour. Exam Pearl: ANC = WBC × (% segs + % bands). Calculate ANC to determine infection risk level.","US"),

  // Infection Control (USA)
  q("NCLEX-RN","Infection Control",2,"A nurse enters a client's room who is on contact precautions for MRSA. The nurse should don:","N95 respirator only|Gloves and gown before entering the room|Surgical mask only|No additional PPE beyond standard precautions".split("|"),1,"Correct: Contact precautions for MRSA require gloves and gown upon entering the room. Dedicated equipment should remain in the room. Hand hygiene is performed after removing PPE. Incorrect: N95 (A) is for airborne precautions. Surgical mask alone (C) is for droplet precautions. Additional PPE beyond standard precautions (D) is required for contact precautions. Clinical Takeaway: Contact precautions apply to: MRSA, VRE, C. diff, scabies, and RSV. Dedicated stethoscope and BP cuff should stay in the room. Exam Pearl: For C. diff specifically, use soap and water for hand hygiene — alcohol-based sanitizers do NOT kill C. diff spores.","US"),

  // Fluid/Electrolytes (USA)
  q("NCLEX-RN","Fluid/Electrolytes",3,"A client's serum calcium is 7.2 mg/dL. The nurse should assess for:","Constipation and kidney stones|Trousseau sign and Chvostek sign (signs of neuromuscular irritability)|Flaccid paralysis|Polyuria and polydipsia".split("|"),1,"Correct: Hypocalcemia (< 8.5 mg/dL) causes increased neuromuscular excitability. Trousseau sign (carpopedal spasm with BP cuff inflation) and Chvostek sign (facial twitching when tapping facial nerve) are classic clinical signs. Incorrect: Constipation and kidney stones (A) are signs of hypercalcemia. Flaccid paralysis (C) is associated with hypokalemia. Polyuria and polydipsia (D) suggest hyperglycemia or hypercalcemia. Clinical Takeaway: Severe hypocalcemia can cause laryngospasm, seizures, and cardiac arrhythmias (prolonged QT). Treatment: IV calcium gluconate (for symptomatic) or oral calcium/vitamin D (for mild). Exam Pearl: Always correct hypomagnesemia before treating hypocalcemia — low magnesium impairs PTH secretion and calcium regulation.","US"),

  // Acid-Base (USA)
  q("NCLEX-RN","Acid-Base",3,"A client has ABG results: pH 7.48, PaCO₂ 30 mmHg, HCO₃⁻ 22 mEq/L. The nurse interprets this as:","Metabolic alkalosis|Respiratory alkalosis|Compensated metabolic acidosis|Normal ABG values".split("|"),1,"Correct: pH > 7.45 (alkalosis), PaCO₂ < 35 (respiratory cause — hyperventilation blowing off CO₂), HCO₃ normal (no renal compensation yet). This is uncompensated respiratory alkalosis. Incorrect: Metabolic alkalosis (A) would show elevated HCO₃. Compensated metabolic acidosis (C) would have low pH or normal with low HCO₃ and low CO₂. These are not normal values (D). Clinical Takeaway: Common causes include anxiety/hyperventilation, pain, mechanical ventilation with excessive rate. Treatment: address underlying cause, coaching slow breathing, possible rebreathing technique. Exam Pearl: Use ROME — Respiratory Opposite (pH up, PaCO₂ down = respiratory alkalosis), Metabolic Equal (pH and HCO₃ move in the same direction).","US"),

  // Diabetes (USA)
  q("NCLEX-RN","Diabetes",2,"A client with type 2 diabetes has an HbA1c of 9.2%. The nurse explains this means:","Blood glucose control has been excellent over the past 3 months|Average blood glucose has been poorly controlled over the past 2–3 months|The client is at low risk for complications|The client does not need medication adjustments".split("|"),1,"Correct: HbA1c reflects average blood glucose over 2–3 months. An HbA1c of 9.2% indicates poor glycemic control (target < 7% for most adults). This corresponds to an estimated average glucose of approximately 220 mg/dL. Incorrect: This is poor control (A), not excellent. Risk for complications is high (C). Medication adjustments are likely needed (D). Clinical Takeaway: Every 1% reduction in HbA1c reduces microvascular complications by approximately 37%. ADA recommends HbA1c testing every 3–6 months. Exam Pearl: HbA1c conversion: 6% ≈ 126 mg/dL average glucose. Each 1% increase ≈ 28 mg/dL increase in average glucose.","US"),
  q("NCLEX-RN","Diabetes",3,"A client with type 1 diabetes is going to exercise vigorously. The nurse should instruct the client to:","Skip insulin before exercising|Eat a carbohydrate snack before exercise and carry fast-acting glucose|Increase insulin dose before exercise|Exercise only when blood glucose is above 300 mg/dL".split("|"),1,"Correct: Exercise increases insulin sensitivity and glucose uptake, increasing hypoglycemia risk. A carbohydrate snack (15–30 g) before exercise prevents hypoglycemia. The client should carry glucose tablets and monitor blood glucose before, during, and after exercise. Incorrect: Skipping insulin (A) can cause hyperglycemia and ketoacidosis. Increasing insulin (C) increases hypoglycemia risk. Exercising above 300 mg/dL (D) with ketones can worsen hyperglycemia. Clinical Takeaway: If blood glucose is > 250 mg/dL, check for ketones — if positive, do NOT exercise. If < 100 mg/dL, eat a carbohydrate snack before starting. Exam Pearl: Exercise can lower blood glucose for up to 24 hours after activity — teach clients about delayed hypoglycemia.","US"),

  // Mental Health (USA)
  q("NCLEX-RN","Mental Health",2,"A nurse is caring for a client who reports auditory hallucinations telling them to harm others. The nurse's priority action is:","Leave the client alone to rest|Assess the client's intention to act on the command hallucinations and ensure safety|Argue with the client that the voices are not real|Administer a PRN anxiolytic immediately".split("|"),1,"Correct: Command hallucinations directing harm to self or others require immediate safety assessment: determine whether the client intends to act, implement safety measures, notify the treatment team, and provide close observation. Incorrect: Leaving the client alone (A) is unsafe. Arguing (C) is non-therapeutic and can escalate agitation. Medications (D) may be needed but assessment comes first. Clinical Takeaway: Never ignore command hallucinations — they significantly increase the risk of violence. Document the content, frequency, and the client's response to the hallucinations. Exam Pearl: Present reality without arguing: 'I understand you hear voices. I don't hear them, but I can see they are distressing for you.'","US"),
  q("NCLEX-RN","Mental Health",3,"A client with a history of suicide attempts is being discharged. The nurse's discharge teaching should include:","Providing a large supply of medications for convenience|Ensuring the client and family have a safety plan with crisis hotline numbers and follow-up appointments|Telling the client that everything will be fine|Discontinuing all psychotropic medications before discharge".split("|"),1,"Correct: A comprehensive discharge safety plan includes identifying warning signs, coping strategies, support persons, crisis contacts (988 Suicide & Crisis Lifeline), means restriction counseling, and scheduled follow-up appointments within 7 days. Incorrect: Large medication supply (A) provides means for overdose. False reassurance (C) is non-therapeutic. Stopping medications abruptly (D) risks relapse and withdrawal. Clinical Takeaway: The transition from inpatient to outpatient care is the highest-risk period for suicide — follow-up within 72 hours reduces risk significantly. Exam Pearl: Means restriction counseling (removing access to firearms, medications, sharp objects) is one of the most effective suicide prevention strategies.","US"),

  // Pediatrics (USA)
  q("NCLEX-RN","Pediatrics",2,"A nurse is assessing a 2-year-old child's growth and development. Which finding would be expected?","Speaking in full sentences of 6+ words|Using 2–3 word phrases and having a vocabulary of approximately 50 words|Reading simple books independently|Counting to 20 accurately".split("|"),1,"Correct: At 2 years, children typically use 2–3 word phrases ('want milk,' 'go bye-bye'), have approximately 50–300 word vocabulary, and can follow simple 2-step commands. Incorrect: Full sentences (A) develop around age 4–5. Reading (C) develops around age 5–6. Counting to 20 (D) develops around age 4–5. Clinical Takeaway: Red flags at 2 years: fewer than 50 words, no 2-word phrases, loss of previously acquired language skills (regression), or lack of response to name. Refer for evaluation. Exam Pearl: Language milestones: 1 year = 2–3 words; 2 years = 2–3 word phrases; 3 years = 3–4 word sentences; 5 years = speaks in complete sentences.","US"),
  q("NCLEX-RN","Pediatrics",3,"A child with a ventricular septal defect (VSD) has symptoms of heart failure. The nurse should monitor for:","Decreased respiratory rate|Tachycardia, tachypnea, diaphoresis during feeding, and poor weight gain|Hypertension and headaches|Cyanosis that worsens with crying".split("|"),1,"Correct: VSD causes left-to-right shunting, increasing pulmonary blood flow and causing congestive heart failure symptoms: tachycardia, tachypnea, hepatomegaly, poor feeding (diaphoresis and fatigue during feeds), and failure to thrive. Incorrect: Decreased respiratory rate (A) is not expected. Hypertension and headaches (C) suggest coarctation of the aorta. Cyanosis with crying (D) suggests right-to-left shunting (cyanotic heart disease). Clinical Takeaway: Small VSDs may close spontaneously. Large VSDs with symptomatic HF require digoxin, diuretics, and eventual surgical repair to prevent Eisenmenger syndrome. Exam Pearl: Acyanotic defects (VSD, ASD, PDA) involve left-to-right shunting. Cyanotic defects (TOF, TGA) involve right-to-left shunting.","US"),

  // Maternity/OB (USA)
  q("NCLEX-RN","Maternity/OB",3,"A client in labor has late decelerations on the fetal monitor. The nurse should:","Continue to monitor without intervention|Reposition the client to the left lateral position, administer oxygen, increase IV fluids, and notify the provider|Prepare for immediate vaginal delivery|Increase the oxytocin infusion rate".split("|"),1,"Correct: Late decelerations indicate uteroplacental insufficiency. Intrauterine resuscitation measures include: left lateral positioning (improves uterine blood flow), oxygen via non-rebreather mask, IV fluid bolus, discontinue oxytocin if infusing, and notify the provider. Incorrect: Monitoring only (A) allows continued fetal compromise. Immediate vaginal delivery (C) may not be possible. Increasing oxytocin (D) worsens uterine hyperstimulation and fetal distress. Clinical Takeaway: If late decelerations persist despite interventions, prepare for emergency cesarean delivery. Repetitive late decelerations are an ominous sign of fetal hypoxia. Exam Pearl: Late decelerations = mirror image of contractions with a delayed onset. They are caused by placental insufficiency, not cord compression.","US"),
  q("NCLEX-RN","Maternity/OB",2,"A nurse is teaching a newly pregnant client about foods to avoid during pregnancy. Which food should be eliminated?","Well-cooked chicken|Raw or undercooked fish (sushi) due to risk of Listeria and mercury exposure|Pasteurized dairy products|Cooked vegetables".split("|"),1,"Correct: Raw/undercooked fish, unpasteurized cheese/dairy, deli meats, and raw sprouts should be avoided due to Listeria, Toxoplasma, and mercury risks. High-mercury fish (shark, swordfish, king mackerel, tilefish) should also be avoided. Incorrect: Well-cooked chicken (A) is safe. Pasteurized dairy (C) is safe. Cooked vegetables (D) are safe and encouraged. Clinical Takeaway: Recommend 8–12 oz/week of low-mercury seafood (salmon, shrimp, tilapia) for omega-3 fatty acids. Folic acid supplementation (400–800 mcg/day) prevents neural tube defects. Exam Pearl: Listeriosis can cause miscarriage, stillbirth, and neonatal sepsis. Pregnant women are 10 times more susceptible to Listeria than the general population.","US"),

  // Postpartum/Newborn (USA)
  q("NCLEX-RN","Postpartum/Newborn",2,"A nurse is performing a newborn assessment. Which finding requires immediate notification of the provider?","Acrocyanosis (bluish hands and feet)|Central cyanosis (bluish discoloration of the trunk and mucous membranes)|Milia on the nose|Erythema toxicum".split("|"),1,"Correct: Central cyanosis indicates inadequate oxygenation and may signal a congenital heart defect or respiratory problem — this is an emergency requiring immediate evaluation. Incorrect: Acrocyanosis (A) is normal in newborns for the first 24–48 hours due to immature peripheral circulation. Milia (C) are benign, blocked sebaceous glands. Erythema toxicum (D) is a benign newborn rash. Clinical Takeaway: Differentiate central cyanosis (pathological — check pulse oximetry, ABG) from peripheral acrocyanosis (normal). Persistent central cyanosis unresponsive to oxygen suggests cyanotic heart disease. Exam Pearl: The hyperoxia test distinguishes cardiac from pulmonary cyanosis — if PaO₂ does not rise above 100 mmHg with 100% oxygen, cardiac disease is likely.","US"),
  q("NCLEX-RN","Postpartum/Newborn",3,"A postpartum client reports saturating a pad every 15 minutes with bright red blood. The nurse's first action is:","Document the finding and continue monitoring|Massage the uterine fundus and assess for uterine atony|Change the pad and reassess in 1 hour|Administer ibuprofen for cramping".split("|"),1,"Correct: Saturating a pad every 15 minutes indicates postpartum hemorrhage. The most common cause is uterine atony. First: massage the fundus to stimulate contraction. Then: assess vital signs, call for help, establish/increase IV access, and prepare to administer uterotonics (oxytocin, methylergonovine, carboprost). Incorrect: Documentation only (A) delays critical intervention. Waiting 1 hour (C) allows life-threatening blood loss. Ibuprofen (D) does not address hemorrhage. Clinical Takeaway: Postpartum hemorrhage is defined as blood loss > 500 mL after vaginal delivery or > 1,000 mL after cesarean. The '4 Ts' of causes: Tone (atony), Tissue (retained placenta), Trauma (lacerations), Thrombin (coagulopathy). Exam Pearl: Uterine atony accounts for 80% of postpartum hemorrhage. A boggy, displaced uterus is the hallmark finding.","US"),

  // Geriatrics (USA)
  q("NCLEX-RN","Geriatrics",2,"An elderly client is prescribed multiple medications by different specialists. The nurse's primary concern is:","The client cannot afford the medications|Polypharmacy increases the risk of adverse drug interactions and falls|The client has too many appointments|The medications are all in different strengths".split("|"),1,"Correct: Polypharmacy (≥ 5 medications) in older adults increases the risk of drug-drug interactions, adverse effects, falls, cognitive impairment, and non-adherence. Medication reconciliation is essential. Incorrect: Cost (A) is a concern but not the primary safety issue. Too many appointments (C) is a logistical concern. Different strengths (D) alone are not the primary concern. Clinical Takeaway: Use the Beers Criteria to identify potentially inappropriate medications in older adults. Perform medication reconciliation at every transition of care. Exam Pearl: Common high-risk medications in elderly: benzodiazepines (fall risk), anticholinergics (confusion), and NSAIDs (GI bleeding, renal impairment).","US"),
  q("NCLEX-RN","Geriatrics",3,"A nurse suspects that an elderly client in a long-term care facility is being neglected. Which finding supports this concern?","The client is clean and well-nourished|The client has poor hygiene, untreated pressure ulcers, and significant weight loss|The client expresses dissatisfaction with food choices|The client prefers to stay in bed".split("|"),1,"Correct: Neglect is indicated by poor hygiene, malnutrition, dehydration, untreated medical conditions, and pressure ulcers from inadequate repositioning. Nurses are mandated reporters and must report suspected neglect. Incorrect: Clean and well-nourished (A) indicates adequate care. Food preference dissatisfaction (C) alone is not neglect. Preferring bed rest (D) is a choice but should be assessed for underlying issues. Clinical Takeaway: Elder abuse/neglect must be reported to the appropriate state authority (Adult Protective Services). Document findings objectively with photographs if permitted. Exam Pearl: Types of elder abuse: physical, emotional/psychological, sexual, financial exploitation, neglect, and abandonment. Nurses are mandated reporters in all 50 states.","US"),

  // Critical Care (USA)
  q("NCLEX-RN","Critical Care",4,"A client in the ICU on mechanical ventilation develops a sudden increase in peak inspiratory pressure with no change in plateau pressure. The nurse suspects:","Decreased lung compliance (pneumothorax, atelectasis)|Increased airway resistance (mucus plug, bronchospasm, kinked ET tube)|Equipment malfunction only|Normal ventilator cycling".split("|"),1,"Correct: Increased peak pressure without plateau pressure change indicates increased airway resistance (obstruction between ventilator and alveoli) — most commonly mucus plug, bronchospasm, or kinked/biting on ET tube. Incorrect: Decreased compliance (A) would increase BOTH peak and plateau pressures. Equipment malfunction (C) is possible but clinical assessment of airway comes first. This is not normal (D). Clinical Takeaway: Suction the airway, check for kinks, assess for bronchospasm (administer bronchodilator), and ensure ET tube position. If plateau pressure also rises, consider pneumothorax, ARDS, or atelectasis. Exam Pearl: Peak pressure = airway resistance + compliance. Plateau pressure = compliance alone. Comparing them localizes the problem.","US"),
  q("NCLEX-RN","Critical Care",4,"A nurse is interpreting hemodynamic data for a client with cardiogenic shock. Expected findings include:","High cardiac output and low SVR|Low cardiac output, high SVR, high PCWP|High cardiac output, high SVR|Low cardiac output, low PCWP".split("|"),1,"Correct: Cardiogenic shock: pump failure leads to decreased cardiac output/index, increased SVR (compensatory vasoconstriction), and elevated PCWP (fluid backs up due to failing left ventricle). Incorrect: High CO/low SVR (A) describes distributive shock (septic). High CO/high SVR (C) is not a typical shock pattern. Low CO/low PCWP (D) describes hypovolemic shock. Clinical Takeaway: Treatment includes inotropes (dobutamine), vasopressors if MAP < 65, IABP for mechanical support, and addressing the underlying cause (PCI for MI). Exam Pearl: Know the hemodynamic profiles: Cardiogenic = ↓CO, ↑SVR, ↑PCWP. Hypovolemic = ↓CO, ↑SVR, ↓PCWP. Septic (warm) = ↑CO, ↓SVR, ↓PCWP.","US"),

  // Emergency Nursing (USA)
  q("NCLEX-RN","Emergency Nursing",2,"A client arrives at the emergency department with a suspected stroke. The nurse should prioritize:","Obtaining a complete medical history before any intervention|Rapid neurological assessment (NIHSS), activating the stroke team, and obtaining a CT scan to rule out hemorrhage|Administering aspirin immediately|Starting IV heparin".split("|"),1,"Correct: Time is critical in stroke ('time is brain'). Priorities: rapid assessment using NIHSS, activate stroke team, stat non-contrast CT to differentiate ischemic vs. hemorrhagic stroke, and determine eligibility for tPA (within 4.5 hours of symptom onset). Incorrect: Complete history (A) delays time-sensitive treatment. Aspirin (C) is given AFTER CT confirms ischemic stroke. Heparin (D) is not first-line for acute stroke. Clinical Takeaway: Door-to-CT time should be < 25 minutes, door-to-needle (tPA) time < 60 minutes. Last known well time determines treatment eligibility. Exam Pearl: The mnemonic BE-FAST helps recognize stroke: Balance, Eyes, Face drooping, Arm weakness, Speech difficulty, Time to call 911.","US"),
  q("NCLEX-RN","Emergency Nursing",3,"A client in the emergency department presents with an anaphylactic reaction after a bee sting. The nurse should administer:","Oral diphenhydramine as first-line treatment|Epinephrine 0.3 mg intramuscularly in the lateral thigh (anterolateral mid-thigh)|IV corticosteroids as the initial intervention|Albuterol nebulizer only".split("|"),1,"Correct: Epinephrine IM is the first-line treatment for anaphylaxis — it reverses bronchospasm, improves blood pressure, and reduces angioedema. Administered in the lateral thigh for optimal absorption. Dose: 0.3–0.5 mg (1:1,000) IM for adults. Incorrect: Oral diphenhydramine (A) is too slow and insufficient for anaphylaxis. Corticosteroids (C) take hours to work and are adjunctive. Albuterol (D) treats bronchospasm but not the systemic reaction. Clinical Takeaway: Repeat epinephrine every 5–15 minutes if symptoms persist. Establish IV access, administer IV fluids for hypotension, and observe for biphasic reaction (4–6 hours minimum). Exam Pearl: Epinephrine auto-injector (EpiPen) delivers 0.3 mg for adults and 0.15 mg for children < 30 kg. Always prescribe 2 auto-injectors at discharge.","US"),

  // Pain Management (USA)
  q("NCLEX-RN","Pain Management",3,"A nurse is caring for a post-surgical client who is opioid-naive and requests pain medication. The nurse should apply which principle?","Administer the strongest opioid available to prevent any pain|Start with the lowest effective dose of opioid and titrate based on pain assessment and response|Withhold opioids and use only non-pharmacological methods|Administer opioids on a fixed schedule regardless of pain level".split("|"),1,"Correct: For opioid-naive patients, start low and go slow — begin with the lowest effective dose, assess pain response, and titrate accordingly. Multimodal analgesia (combining non-opioid and opioid approaches) is the current standard. Incorrect: Strongest opioid (A) increases adverse effect risk. Withholding opioids entirely (C) may undertread pain. Fixed schedule without assessment (D) ignores individual response. Clinical Takeaway: Multimodal analgesia combines: acetaminophen, NSAIDs, regional anesthesia, opioids, and non-pharmacological methods (ice, positioning, relaxation). This reduces total opioid requirement. Exam Pearl: Monitor sedation level before respiratory rate — sedation is the earliest sign of opioid toxicity and precedes respiratory depression.","US"),

  // Wound Care (USA)
  q("NCLEX-RN","Wound Care",2,"A nurse is assessing a surgical wound on postoperative day 2 and notes the wound edges are approximated with slight redness and serous drainage. This indicates:","Wound infection requiring antibiotics|Normal wound healing by primary intention|Wound dehiscence|Wound necrosis".split("|"),1,"Correct: Primary intention healing (wound edges approximated/sutured) normally shows slight redness (inflammation phase), serous (clear, yellow) drainage, and mild swelling in the first 1–3 days. These are normal inflammatory responses. Incorrect: Infection (A) shows purulent drainage, increased pain, erythema beyond wound edges, and fever. Dehiscence (C) involves wound edge separation. Necrosis (D) shows black, devitalized tissue. Clinical Takeaway: Normal wound healing phases: hemostasis (minutes), inflammation (1–4 days), proliferation (4–21 days), maturation (21 days–2 years). Exam Pearl: Warning signs of wound infection: increased pain after day 2–3, purulent drainage, erythema spreading > 2 cm from wound edge, fever, and elevated WBC.","US"),

  // Medication Administration (USA)
  q("NCLEX-RN","Medication Administration",2,"A nurse is preparing to administer insulin using two types in the same syringe (regular and NPH). The nurse should:","Draw up NPH insulin first, then regular insulin|Draw up clear (regular) insulin first, then cloudy (NPH) insulin|Mix the two insulins in separate syringes|Never mix insulins together".split("|"),1,"Correct: When mixing insulins in one syringe, always draw up clear (regular/fast-acting) before cloudy (NPH) to prevent contamination of the regular insulin vial with NPH, which would alter the regular insulin's onset time. Incorrect: Drawing NPH first (A) contaminates the regular vial. Separate syringes (C) increase injection frequency unnecessarily. Mixing is appropriate for regular + NPH (D). Clinical Takeaway: Remember 'clear before cloudy.' Never mix insulin glargine (Lantus) or insulin detemir (Levemir) with other insulins — they must be given separately. Exam Pearl: After mixing, the injection should be administered immediately. Roll NPH gently before drawing — do not shake vigorously.","US"),

  // Patient Safety (USA)
  q("NCLEX-RN","Patient Safety",2,"Before administering a blood transfusion, two nurses must verify:","Only the client's name|Client identity (two identifiers), blood type, Rh factor, crossmatch compatibility, expiration date, and unit number with the provider order|Only the blood type|The client's room number and bed assignment".split("|"),1,"Correct: Two licensed nurses must verify at the bedside: client identity (name + DOB or MRN), prescribed blood component, ABO/Rh compatibility, crossmatch results, unit number matching the blood bank tag, and expiration date. Incorrect: Name alone (A) is insufficient — two identifiers are required. Blood type alone (C) does not include crossmatch verification. Room number (D) is never used as an identifier. Clinical Takeaway: Start the transfusion slowly (first 15 minutes at reduced rate), stay with the client for the first 15 minutes, and monitor vital signs per protocol. Most fatal reactions occur within the first 50 mL. Exam Pearl: If a transfusion reaction occurs: STOP the transfusion immediately, keep the IV line open with normal saline (new tubing), and notify the provider and blood bank.","US"),

  // Delegation/Prioritization (USA)
  q("NCLEX-RN","Delegation/Prioritization",3,"A nurse is triaging four clients in the emergency department. Which client should be seen first?","A client with a sprained ankle and pain rated 6/10|A client with chest pain, diaphoresis, and nausea|A client with a laceration requiring 3 sutures|A client with a urinary tract infection and low-grade fever".split("|"),1,"Correct: Chest pain with diaphoresis and nausea suggests acute myocardial infarction — a life-threatening emergency requiring immediate assessment and intervention (ECG, cardiac markers, aspirin, possible cath lab activation). Incorrect: Sprained ankle (A) is non-emergent. Laceration (C) is urgent but not life-threatening. UTI with low-grade fever (D) is less urgent. Clinical Takeaway: Triage priority uses the Emergency Severity Index (ESI): Level 1 (resuscitation), Level 2 (emergent), Level 3 (urgent), Level 4 (less urgent), Level 5 (non-urgent). Exam Pearl: ABC (Airway, Breathing, Circulation) determines priority — chest pain = circulation problem = high priority.","US"),
  q("NCLEX-RN","Delegation/Prioritization",2,"A registered nurse can delegate which task to an unlicensed assistive personnel (UAP)?","Performing the initial client assessment on admission|Recording intake and output measurements for a stable client|Administering oral medications|Educating a client about a new diagnosis".split("|"),1,"Correct: I&O measurement on a stable client is a routine, repetitive task within the UAP's scope after proper training and with RN supervision. Incorrect: Initial assessment (A) requires RN clinical judgment. Medication administration (C) requires a licensed professional. Client education (D) requires RN knowledge and assessment of comprehension. Clinical Takeaway: The Five Rights of Delegation: Right task, Right circumstance, Right person, Right direction/communication, Right supervision/evaluation. Exam Pearl: The RN always retains accountability for delegated tasks. Delegation does not transfer responsibility — the RN must evaluate outcomes.","US"),

  // Leadership/Collaboration (USA)
  q("NCLEX-RN","Leadership/Collaboration",3,"A nurse is assigned as charge nurse for the shift. A conflict arises between two staff members about patient assignments. The charge nurse should:","Ignore the conflict and let them work it out|Address the conflict promptly by listening to both perspectives and facilitating a collaborative resolution|Take over both nurses' assignments|Report both nurses to the manager immediately".split("|"),1,"Correct: Effective conflict resolution involves addressing the issue promptly, actively listening to both parties, identifying the underlying concern, and facilitating a solution that prioritizes patient safety and team function. Incorrect: Ignoring conflict (A) allows it to escalate and affects patient care. Taking over assignments (C) is impractical and does not resolve the issue. Immediate reporting to management (D) is premature without attempting resolution first. Clinical Takeaway: Conflict resolution styles: collaborating (win-win) is preferred for important issues. Compromising is useful when time is limited. Avoiding is appropriate only for trivial matters. Exam Pearl: The charge nurse role includes resource management, conflict resolution, delegation oversight, and facilitating communication between the care team and administration.","US"),

  // Ethical/Legal Practice (USA)
  q("NCLEX-RN","Ethical/Legal Practice",3,"A nurse discovers that a client's advance directive states 'do not resuscitate.' The client goes into cardiac arrest while the family demands CPR. The nurse should:","Follow the family's wishes and initiate CPR|Follow the advance directive and do not initiate CPR|Wait for the physician to decide|Leave the room and avoid the situation".split("|"),1,"Correct: The advance directive represents the client's autonomous wishes made while competent. The nurse is legally and ethically obligated to follow the DNR order. The physician should be notified and the family should be supported through the grieving process. Incorrect: Following family wishes (A) violates the client's documented autonomy. Waiting for the physician (C) delays appropriate action. Avoiding the situation (D) is abandonment. Clinical Takeaway: Advance directives include living wills and durable power of attorney for healthcare. They must be honored unless revoked by the competent client. Exam Pearl: The Patient Self-Determination Act (1990) requires healthcare facilities to inform clients of their right to make advance directives and to document whether one exists.","US"),
  q("NCLEX-RN","Ethical/Legal Practice",4,"A nurse witnesses a colleague charting a medication as given when it was not administered. This constitutes:","A minor documentation error|Falsification of medical records, which is a legal offense and grounds for disciplinary action|Acceptable practice if the nurse plans to give it later|A confidential matter between nurses".split("|"),1,"Correct: Documenting a medication as given when it was not is falsification of medical records — a legal offense that can result in license revocation, criminal charges, and malpractice liability. It also puts the client at risk for missed doses. Incorrect: This is not minor (A) — it is fraud and patient endangerment. Planning to give it later (C) does not justify false documentation. This must be reported (D) — it is not a matter to keep confidential. Clinical Takeaway: The nurse has an obligation to report this to the supervisor. Document only what you personally observe and perform. Never chart ahead or for another nurse. Exam Pearl: The four elements of malpractice: duty (nurse-client relationship), breach (deviation from standard of care), causation (breach caused harm), and damages (measurable harm occurred).","US"),

  // Additional USA topics to reach 75
  // Cardiovascular (USA)
  q("NCLEX-RN","Cardiovascular",4,"A client with third-degree (complete) heart block has a ventricular rate of 30 bpm. The nurse should prepare for:","Observation and monitoring only|Transcutaneous pacing and preparation for a temporary or permanent pacemaker|Cardioversion|Adenosine administration".split("|"),1,"Correct: Complete heart block with symptomatic bradycardia (rate 30 bpm) is an emergency requiring transcutaneous pacing as a bridge to transvenous pacing or permanent pacemaker implantation. Atropine may be attempted but is often ineffective in third-degree block. Incorrect: Observation only (A) is inappropriate for symptomatic complete heart block. Cardioversion (C) is for tachyarrhythmias. Adenosine (D) is for SVT, not bradycardia. Clinical Takeaway: Complete heart block shows P waves and QRS complexes beating independently (AV dissociation). Atrial rate is faster than ventricular rate. Wide QRS indicates block below the His bundle. Exam Pearl: ACLS algorithm for symptomatic bradycardia: atropine first (if no delay for pacing), transcutaneous pacing, dopamine or epinephrine drip as alternatives.","US"),

  // Respiratory (USA)
  q("NCLEX-RN","Respiratory",4,"A client on mechanical ventilation develops sudden respiratory distress, absent breath sounds on the left, and tracheal deviation to the right. The nurse suspects:","Left-sided pneumonia|Left-sided tension pneumothorax|Right-sided pleural effusion|Normal ventilator findings".split("|"),1,"Correct: Absent breath sounds on one side with tracheal deviation to the opposite side indicates tension pneumothorax — air accumulates under pressure, compressing the affected lung and shifting the mediastinum. This is immediately life-threatening. Incorrect: Pneumonia (A) would not cause tracheal deviation. Right-sided effusion (C) would affect the right side. These are not normal findings (D). Clinical Takeaway: Tension pneumothorax requires emergent needle decompression (14–16 gauge needle in the 2nd intercostal space, midclavicular line) followed by chest tube placement. Exam Pearl: Risk factors for ventilator-associated pneumothorax include high PEEP, high tidal volumes, and underlying bullous lung disease (COPD, cystic fibrosis).","US"),

  // Pharmacology (USA)
  q("NCLEX-RN","Pharmacology",3,"A client taking digoxin reports seeing yellow-green halos around lights and has a heart rate of 54 bpm. The nurse should:","Give the next dose as scheduled|Hold the digoxin and notify the provider as these are signs of digoxin toxicity|Administer an additional dose for better heart rate control|Instruct the client to eat more potassium-rich foods".split("|"),0,"Correct: Visual disturbances (yellow-green halos, blurred vision) and bradycardia are classic signs of digoxin toxicity. Hold the medication, check digoxin level (therapeutic: 0.5–2.0 ng/mL), check potassium (hypokalemia increases toxicity risk), and notify the provider. Incorrect: Giving the next dose (A) worsens toxicity. Additional doses (C) are dangerous. Potassium (D) is important but does not address the acute toxicity. Clinical Takeaway: Digoxin toxicity antidote: digoxin immune Fab (Digibind). Common toxicity triggers: hypokalemia, hypomagnesemia, renal impairment, and drug interactions (amiodarone, verapamil). Exam Pearl: Always check apical pulse for 60 seconds before giving digoxin — hold if HR < 60 bpm in adults or < 100 bpm in infants.","US"),

  // Infection Control (USA)
  q("NCLEX-RN","Infection Control",3,"A client with varicella (chickenpox) requires which type of isolation precautions?","Contact precautions only|Airborne AND contact precautions|Droplet precautions only|Standard precautions only".split("|"),1,"Correct: Varicella is transmitted by both airborne route (varicella-zoster virus in respiratory droplet nuclei) and direct contact (vesicular fluid). Both airborne precautions (N95, negative-pressure room) and contact precautions (gown, gloves) are required. Incorrect: Contact only (A) misses the airborne transmission. Droplet precautions (C) are insufficient for airborne organisms. Standard precautions alone (D) are inadequate. Clinical Takeaway: Only immune healthcare workers (history of varicella or positive varicella titer) should care for these clients. Non-immune exposed staff should be furloughed days 10–21 post-exposure. Exam Pearl: Diseases requiring airborne precautions: TB, measles, varicella, and disseminated herpes zoster. Remember: 'My Chicken Hez TB' — Measles, Chickenpox, Herpes zoster (disseminated), TB.","US"),

  // Fluid/Electrolytes (USA)
  q("NCLEX-RN","Fluid/Electrolytes",2,"A client is receiving IV normal saline (0.9% NaCl). The nurse understands this is an isotonic solution used to:","Pull fluid from the intravascular space into cells|Expand intravascular volume without shifting fluid into cells|Provide calories for nutrition|Correct hypernatremia by diluting sodium".split("|"),1,"Correct: Isotonic solutions (0.9% NS, lactated Ringer's) have the same osmolality as body fluids and stay in the intravascular space, expanding blood volume without causing fluid shifts between compartments. Incorrect: Pulling fluid into cells (A) describes hypotonic solutions. NS does not provide significant calories (C). It does not correct hypernatremia (D) — hypotonic solutions are used for that. Clinical Takeaway: Isotonic = volume expansion (dehydration, hemorrhage). Hypotonic (0.45% NS) = cellular dehydration. Hypertonic (3% NS) = draws fluid from cells (cerebral edema). Exam Pearl: D5W is isotonic in the bag but becomes hypotonic once infused (dextrose is quickly metabolized, leaving free water).","US"),

  // Maternity/OB (USA)
  q("NCLEX-RN","Maternity/OB",4,"A nurse is caring for a client receiving magnesium sulfate for severe preeclampsia. The nurse should hold the infusion and notify the provider if:","Urine output is 40 mL/hour|Deep tendon reflexes are absent|The client reports feeling warm|Blood pressure is 150/95 mmHg".split("|"),1,"Correct: Absent deep tendon reflexes indicate magnesium toxicity. The sequence of toxicity: loss of DTRs (therapeutic is diminished but present) → respiratory depression → cardiac arrest. Hold magnesium if DTRs are absent, RR < 12, or urine output < 30 mL/hour. Incorrect: Urine output 40 mL/hour (A) is adequate. Feeling warm (C) is a normal side effect (vasodilation). BP 150/95 (D) is still elevated and does not indicate magnesium toxicity. Clinical Takeaway: Therapeutic magnesium level: 4–7 mg/dL. Antidote: calcium gluconate 1 g IV (keep at bedside). Monitor DTRs hourly, RR, urine output, and fetal heart rate. Exam Pearl: Remember the toxicity sequence by magnesium level: DTR loss (8–12 mg/dL), respiratory depression (12–15 mg/dL), cardiac arrest (> 20 mg/dL).","US"),

  // Wound Care (USA)
  q("NCLEX-RN","Wound Care",3,"A client with a venous stasis ulcer on the lower leg should be treated with:","Arterial bypass surgery|Compression therapy (compression wraps or stockings) to promote venous return|Elevation of the leg above the heart at all times without compression|Application of heat to the wound".split("|"),1,"Correct: Venous stasis ulcers result from venous insufficiency causing venous hypertension and tissue damage. Compression therapy (30–40 mmHg) is the cornerstone of treatment, improving venous return and reducing edema. Incorrect: Arterial bypass (A) is for arterial ulcers, not venous. Elevation alone without compression (C) is insufficient. Heat (D) can damage fragile tissue and worsen edema. Clinical Takeaway: Before applying compression, confirm adequate arterial circulation (ABI > 0.8). Compression on an arterially compromised limb can cause tissue ischemia. Exam Pearl: Venous ulcers: medial malleolus, irregular borders, heavy exudate, brownish skin discoloration. Arterial ulcers: distal (toes, foot), well-defined borders, minimal exudate, pale wound bed.","US"),

  // Patient Safety (USA)
  q("NCLEX-RN","Patient Safety",3,"A nurse notices that the wrong medication was dispensed by the pharmacy for a client. The nurse should:","Administer the medication anyway since the pharmacy approved it|Do not administer the medication, notify the pharmacy and prescriber, and file a safety report|Document the error but administer the medication|Discard the medication without notifying anyone".split("|"),1,"Correct: The nurse is the last line of defense in medication safety. A medication error caught before administration should still be reported (near-miss) to improve system safety. Notify the pharmacy and prescriber, obtain the correct medication. Incorrect: Administering the wrong medication (A) harms the client. Administering with documentation (C) still harms the client. Discarding without reporting (D) misses the opportunity to prevent future errors. Clinical Takeaway: Near-miss events should be reported through the facility's safety reporting system — they identify systemic vulnerabilities before actual harm occurs. Exam Pearl: The nurse is legally responsible for verifying the Five (or Seven) Rights of medication administration — 'the pharmacy sent it' is not a defense for administering the wrong medication.","US"),

  // Delegation (USA)
  q("NCLEX-RN","Delegation/Prioritization",3,"After receiving morning report, the nurse should see which client first?","A client with a blood glucose of 180 mg/dL before breakfast|A client with new-onset confusion and oxygen saturation of 89%|A client requesting a scheduled PRN laxative|A client waiting for discharge paperwork".split("|"),1,"Correct: New-onset confusion with low SpO₂ (89%) suggests an acute change in condition — possibly hypoxia, sepsis, stroke, or medication reaction. This requires immediate assessment using ABCs. Incorrect: Blood glucose 180 mg/dL (A) is elevated but not emergent for a diabetic client. Laxative request (C) can wait. Discharge paperwork (D) is lowest priority. Clinical Takeaway: When prioritizing clients, look for: acute changes (new symptoms), unstable vital signs, and threats to airway, breathing, or circulation. Stable, chronic conditions are lower priority. Exam Pearl: NCLEX prioritization tip: the answer that involves a new or worsening symptom is usually the highest priority. 'New-onset' is a key trigger word.","US"),

  // Leadership (USA)
  q("NCLEX-RN","Leadership/Collaboration",2,"A nurse is preparing to give a shift handoff report. Essential information to include is:","Only abnormal findings|Client name, diagnosis, current status, recent changes, pending tests/results, IV access, and plan of care|A complete history from admission to present|Personal opinions about the client's behavior".split("|"),1,"Correct: Effective handoff communication includes: client identification, diagnosis, current status and assessment, significant changes, medications/IVs, pending lab/test results, and plan of care. Use SBAR format for concise, structured communication. Incorrect: Only abnormal findings (A) misses important baseline information. Complete history from admission (C) is too lengthy and includes irrelevant information. Personal opinions (D) are inappropriate and biased. Clinical Takeaway: Poor handoff communication is a leading cause of sentinel events (Joint Commission). Standardized handoff tools (I-PASS, SBAR) reduce errors. Exam Pearl: The Joint Commission's National Patient Safety Goals include improving effectiveness of communication among caregivers, specifically during handoffs.","US"),

  // Ethical/Legal (USA)
  q("NCLEX-RN","Ethical/Legal Practice",2,"A nurse is asked to obtain informed consent for a surgical procedure. The nurse's role is to:","Explain the surgical procedure and its risks in detail|Witness the client's signature after the physician has explained the procedure and verify client understanding|Perform the surgery|Decide whether the client needs the surgery".split("|"),1,"Correct: The physician/surgeon is responsible for explaining the procedure, risks, benefits, and alternatives. The nurse witnesses the signature, verifies the client's understanding, and ensures the consent is truly informed and voluntary. Incorrect: Explaining the procedure (A) is the physician's responsibility. Performing surgery (C) and deciding on surgery (D) are not nursing roles. Clinical Takeaway: For consent to be valid, the client must be competent, informed (risks, benefits, alternatives), voluntary (no coercion), and of legal age (or have a legal guardian consent). Exam Pearl: If a client expresses confusion about the procedure after the surgeon leaves, the nurse should NOT have them sign — notify the surgeon to return and provide additional explanation.","US"),

  // Additional questions to reach 75 USA
  // Pharmacology (USA)
  q("NCLEX-RN","Pharmacology",2,"A client is prescribed a nitroglycerin sublingual tablet for chest pain. The nurse instructs the client to:","Swallow the tablet with water|Place the tablet under the tongue and do not swallow; if pain is not relieved in 5 minutes, take another tablet (up to 3 total)|Chew the tablet for faster absorption|Take the tablet with food".split("|"),1,"Correct: Sublingual nitroglycerin dissolves under the tongue for rapid absorption into the bloodstream. If chest pain is not relieved in 5 minutes, take a second tablet. After the third tablet (total 15 minutes), call 911 if pain persists. Incorrect: Swallowing (A) reduces effectiveness. Chewing (C) is not the correct route. Taking with food (D) is for oral medications, not sublingual. Clinical Takeaway: Store nitroglycerin in the original dark glass container. Replace every 6 months. A tingling or burning sensation under the tongue indicates the tablet is potent. Exam Pearl: Nitroglycerin causes hypotension — sit or lie down before taking. Do NOT use with PDE5 inhibitors (sildenafil, tadalafil) — severe, life-threatening hypotension can occur.","US"),

  // Neurological (USA)
  q("NCLEX-RN","Neurological",4,"A client with bacterial meningitis is being treated with IV antibiotics. The nurse monitors for signs of increased intracranial pressure, which include:","Polyuria and polydipsia|Decreased level of consciousness, headache, vomiting, and Cushing triad (hypertension, bradycardia, irregular respirations)|Tachycardia and hypotension|Peripheral edema and weight gain".split("|"),1,"Correct: Increased ICP signs include altered LOC (earliest sign), headache (worse in morning), projectile vomiting, papilledema, and Cushing triad (late sign: widening pulse pressure/hypertension, bradycardia, irregular respirations). Incorrect: Polyuria/polydipsia (A) suggest DI or diabetes. Tachycardia/hypotension (C) is the opposite of Cushing triad. Peripheral edema (D) is not an ICP sign. Clinical Takeaway: Elevate HOB 30 degrees, maintain midline head position, avoid coughing/straining, administer osmotic diuretics (mannitol) as ordered, and monitor neurological status with serial GCS assessments. Exam Pearl: Cushing triad is a LATE sign of increased ICP indicating brainstem herniation is imminent — it requires immediate intervention.","US"),

  // Pediatrics (USA)
  q("NCLEX-RN","Pediatrics",4,"A child with type 1 diabetes at school develops confusion, diaphoresis, and tremors. The school nurse should:","Administer insulin immediately|Give the child fast-acting sugar (juice, glucose tablets) immediately|Call 911 without providing treatment|Have the child exercise to lower blood sugar".split("|"),1,"Correct: Confusion, diaphoresis, and tremors are classic hypoglycemia symptoms. Immediate treatment is 15 g fast-acting carbohydrate (4 oz juice, glucose tablets). If the child becomes unconscious, administer glucagon if available and call 911. Incorrect: Insulin (A) would further lower blood glucose — this is the opposite of what's needed. Calling 911 without treatment (C) delays critical intervention. Exercise (D) would worsen hypoglycemia. Clinical Takeaway: Schools should have an individualized diabetes management plan with glucagon availability, trained staff, and emergency protocols. Recheck glucose 15 minutes after treatment. Exam Pearl: Hypoglycemia = cold, clammy, shaky (adrenergic response). Hyperglycemia = hot, dry, fruity breath (DKA). Remember: 'Cold and clammy, need some candy.'","US"),

  // Mental Health (USA)
  q("NCLEX-RN","Mental Health",3,"A nurse is caring for a client who was recently sexually assaulted. The priority nursing intervention is:","Immediately question the client about the details of the assault|Provide a safe, private environment and offer emotional support while preserving forensic evidence|Encourage the client to shower before the examination|Notify law enforcement before obtaining client consent".split("|"),1,"Correct: Priority care includes creating a safe environment, providing emotional support, obtaining informed consent before examination, preserving forensic evidence (no showering, eating, or changing clothes), and following SANE (Sexual Assault Nurse Examiner) protocol. Incorrect: Questioning details immediately (A) is re-traumatizing. Showering (C) destroys forensic evidence. Law enforcement notification (D) requires client consent (in most states for adult victims). Clinical Takeaway: Offer emergency contraception, STI prophylaxis, HIV PEP, and mental health referrals. Document injuries objectively using body maps and photographs with consent. Exam Pearl: The nurse should use trauma-informed care principles: safety, trustworthiness, choice, collaboration, and empowerment. Avoid asking 'why' questions.","US"),

  // Geriatrics (USA)
  q("NCLEX-RN","Geriatrics",3,"A nurse is assessing an elderly client who presents with acute confusion that developed over the past 24 hours. This presentation is most consistent with:","Dementia|Delirium requiring urgent investigation for the underlying cause|Normal aging|Depression".split("|"),1,"Correct: Delirium is characterized by acute onset, fluctuating level of consciousness, disorientation, and is REVERSIBLE when the underlying cause is treated (infection, medication, electrolyte imbalance, dehydration, urinary retention, pain). Incorrect: Dementia (A) has a gradual onset over months to years. Normal aging (C) does not cause acute confusion. Depression (D) presents differently with persistent sad mood. Clinical Takeaway: Use the Confusion Assessment Method (CAM) to diagnose delirium. Common causes in elderly: UTI, pneumonia, medication changes (especially anticholinergics, opioids, benzodiazepines), and metabolic derangements. Exam Pearl: Delirium vs. dementia: Delirium = acute onset, fluctuating, reversible. Dementia = gradual onset, progressive, usually irreversible. They can coexist (delirium superimposed on dementia).","US"),

  // Endocrine (USA)
  q("NCLEX-RN","Endocrine",4,"A client is post-thyroidectomy. The nurse should keep which emergency equipment at the bedside?","A nasogastric tube|A tracheostomy tray and IV calcium gluconate|An oral airway only|A chest tube insertion kit".split("|"),1,"Correct: Post-thyroidectomy emergencies include: laryngeal edema/hemorrhage causing airway obstruction (tracheostomy tray needed) and hypocalcemia from inadvertent parathyroid removal (IV calcium gluconate needed). Incorrect: NG tube (A) is not the priority emergency equipment. Oral airway alone (C) is insufficient for neck hematoma compression. Chest tube kit (D) is not specifically indicated. Clinical Takeaway: Monitor for: respiratory distress (stridor, swelling), hypocalcemia (tingling, Chvostek/Trousseau signs), and hoarseness (recurrent laryngeal nerve damage). Check posterior dressing for hidden bleeding. Exam Pearl: After thyroidectomy, assess voice quality (ask the client to speak) — hoarseness may indicate recurrent laryngeal nerve injury. If bilateral nerve damage occurs, immediate tracheostomy is needed.","US"),

  // Additional CAN questions (5 more to reach 75)
  q("RN-CAT","Fundamentals",3,"A nurse is preparing to insert an indwelling urinary catheter. Which action demonstrates proper technique?","Inflate the balloon before insertion to test it, then deflate|Maintain strict aseptic technique throughout the entire procedure|Use clean technique as the bladder is not a sterile environment|Insert the catheter without lubricant for easier visualization".split("|"),1,"Correct: Indwelling urinary catheter insertion requires strict aseptic (sterile) technique to prevent catheter-associated urinary tract infections (CAUTI), which are among the most common healthcare-associated infections. Incorrect: Balloon testing before insertion (A) is no longer recommended by most current guidelines. Clean technique (C) is insufficient — sterile technique is required. Lubricant (D) is essential for comfort and to prevent urethral trauma. Clinical Takeaway: CAUTI prevention bundle includes: avoid unnecessary catheterization, maintain closed drainage system, daily review of catheter necessity, and remove as soon as possible. Exam Pearl: In Canada, CAUTI prevention follows Safer Healthcare Now! guidelines, which align with evidence-based practice for infection prevention.","CAN"),
  q("RN-CAT","Respiratory",3,"A client with a tracheostomy develops a mucus plug causing acute respiratory distress. The nurse's first action is:","Call a code blue immediately|Attempt to suction the tracheostomy tube to clear the mucus plug|Remove the tracheostomy tube and replace it with a new one|Administer supplemental oxygen via nasal prongs".split("|"),1,"Correct: Suctioning is the first-line intervention for a mucus plug in a tracheostomy. Use sterile technique, insert the catheter without suction, apply suction while withdrawing for no more than 10–15 seconds. If suctioning fails, remove the inner cannula if applicable. Incorrect: Calling a code (A) may be needed but suctioning should be attempted first. Removing the tube (C) is a last resort if suctioning fails and the client deteriorates. Nasal prongs (D) will not bypass the obstruction. Clinical Takeaway: Humidification of inspired air prevents mucus plugs. Regular tracheostomy care and suctioning as needed maintain airway patency. Exam Pearl: Pre-oxygenate with 100% O₂ for 30 seconds before suctioning. Limit each suction pass to 10–15 seconds to prevent hypoxia.","CAN"),
  q("RN-CAT","Renal",3,"A client with end-stage kidney disease has a serum potassium of 6.2 mmol/L. The nurse should anticipate treatment with:","Oral potassium supplements|IV calcium gluconate to stabilize the myocardium, followed by insulin and dextrose to shift potassium intracellularly|Increased dietary potassium|Fluid restriction alone".split("|"),1,"Correct: Hyperkalaemia > 6.0 mmol/L is a medical emergency. IV calcium gluconate stabilises cardiac membranes (does not lower K⁺). Insulin with dextrose shifts K⁺ intracellularly. Sodium polystyrene sulfonate or patiromer bind GI potassium. Haemodialysis removes K⁺ definitively. Incorrect: Potassium supplements (A) would worsen the condition. Increased dietary K⁺ (C) is contraindicated. Fluid restriction alone (D) does not address hyperkalaemia. Clinical Takeaway: ECG changes in hyperkalaemia: peaked T waves → widened QRS → loss of P waves → sine wave pattern → cardiac arrest. Continuous cardiac monitoring is essential. Exam Pearl: In Canada, potassium is reported in mmol/L (same numeric value as mEq/L). Normal range: 3.5–5.0 mmol/L.","CAN"),
  q("RN-CAT","Geriatrics",4,"A nurse is caring for an elderly client with moderate dementia who becomes agitated in the evening. This phenomenon is known as:","Depression|Sundowning — increased confusion and agitation in the late afternoon and evening|Normal sleep pattern changes|Medication side effects only".split("|"),1,"Correct: Sundowning is characterised by increased confusion, agitation, and behavioural disturbances in the late afternoon and evening in clients with dementia. Contributing factors include fatigue, reduced lighting, disrupted circadian rhythm, and overstimulation. Incorrect: Depression (A) presents differently with persistent low mood. Normal sleep changes (C) do not explain the specific evening pattern. While medications (D) can contribute, sundowning is a recognised dementia phenomenon. Clinical Takeaway: Management includes maintaining a consistent routine, increasing afternoon lighting, reducing stimulation in the evening, ensuring adequate daytime activity, and avoiding caffeine. Non-pharmacological interventions are first-line. Exam Pearl: Antipsychotics for dementia-related agitation carry a black box warning for increased mortality in elderly clients and should be used only as a last resort for severe symptoms.","CAN"),
  q("RN-CAT","Endocrine",4,"A client with Graves disease develops exophthalmos. The nurse should implement which interventions?","No specific eye care is needed|Artificial tears, sunglasses for light sensitivity, elevating the head of bed to reduce periorbital oedema, and possible taping eyelids closed at night|Eye patching 24 hours a day|Administering antibiotic eye drops prophylactically".split("|"),1,"Correct: Exophthalmos in Graves disease (thyroid eye disease) causes corneal exposure, dryness, and risk of ulceration. Interventions include: artificial tears/lubricant, sunglasses (photophobia), HOB elevation (reduces oedema), taping lids at night if they do not close fully, and ophthalmology referral. Incorrect: Eye care is essential (A) to prevent corneal damage. 24-hour patching (C) is excessive and unnecessary. Prophylactic antibiotics (D) are not indicated without infection. Clinical Takeaway: Exophthalmos may not resolve even after treatment of hyperthyroidism and may worsen with radioactive iodine therapy. Severe cases may require orbital decompression surgery. Exam Pearl: Graves disease is the most common cause of bilateral exophthalmos. Unilateral proptosis requires investigation for orbital tumour or infection.","CAN"),

  // Additional US questions (9 more to reach 75)
  q("NCLEX-RN","Cardiovascular",3,"A client with heart failure is prescribed furosemide (Lasix). The nurse should monitor for:","Hyperkalemia|Hypokalemia, hypotension, and ototoxicity|Hypernatremia|Weight gain".split("|"),1,"Correct: Furosemide (loop diuretic) causes potassium, sodium, calcium, and magnesium wasting. Hypokalemia increases digoxin toxicity risk. Ototoxicity (hearing loss) can occur, especially with high doses or concurrent aminoglycoside use. Incorrect: Hyperkalemia (A) is the opposite effect. Hypernatremia (C) — furosemide causes sodium loss. Weight gain (D) — diuretics cause weight loss. Clinical Takeaway: Teach clients to eat potassium-rich foods (bananas, oranges, potatoes) unless contraindicated. Potassium supplements may be prescribed concurrently. Weigh daily and report gain > 2 lbs/day. Exam Pearl: Loop diuretics (furosemide, bumetanide) work on the ascending loop of Henle. Remember: 'Loops Lose calcium.' Thiazides cause calcium retention.","US"),
  q("NCLEX-RN","Respiratory",3,"A nurse is caring for a client with a chest tube connected to a water-seal drainage system. Which finding requires immediate intervention?","Gentle bubbling in the suction control chamber|Drainage system is below the level of the client's chest|Absence of fluctuation (tidaling) in the water-seal chamber|150 mL of sanguineous drainage over the past 8 hours".split("|"),2,"Correct: Absence of tidaling (fluid level rise and fall with respirations) in the water-seal chamber may indicate the tube is obstructed (kinked, clamped, or clotted) or the lung has fully re-expanded. The nurse should assess tubing for obstruction and notify the provider. Incorrect: Gentle bubbling in suction chamber (A) indicates proper suction function. System below chest level (B) is correct positioning (gravity drainage). 150 mL drainage in 8 hours (D) is within normal limits (report > 100 mL/hour). Clinical Takeaway: Continuous bubbling in the water-seal chamber indicates an air leak. Intermittent bubbling with expiration or coughing is normal. Exam Pearl: Never clamp a chest tube without a specific order — clamping can cause tension pneumothorax. If the drainage system breaks, submerge the tube end in sterile water.","US"),
  q("NCLEX-RN","Gastrointestinal",3,"A client is being prepared for a colonoscopy. The nurse should ensure the client understands that bowel preparation includes:","Eating a high-fiber diet the day before|Clear liquid diet the day before, prescribed bowel-cleansing solution, and NPO after midnight|No preparation is needed for colonoscopy|A regular diet until 2 hours before the procedure".split("|"),1,"Correct: Complete bowel preparation ensures adequate visualization during colonoscopy. This includes: clear liquid diet the day before, drinking the prescribed prep solution (polyethylene glycol or sodium phosphate), and NPO after midnight or per institutional protocol. Incorrect: High-fiber diet (A) would impair visualization. No preparation (C) would prevent adequate examination. Regular diet until 2 hours before (D) is insufficient preparation. Clinical Takeaway: Inadequate bowel preparation is the most common reason for incomplete colonoscopy. Ensure the client understands the importance of completing the entire prep solution. Exam Pearl: After the procedure, monitor for complications: abdominal distension, pain, rectal bleeding, and signs of perforation (fever, rigid abdomen, tachycardia).","US"),
  q("NCLEX-RN","Musculoskeletal",2,"A client with osteoporosis is prescribed alendronate (Fosamax). The nurse should instruct the client to:","Take the medication with a full meal|Take the medication first thing in the morning on an empty stomach with a full glass of water and remain upright for 30 minutes|Take the medication at bedtime and lie down immediately|Take the medication with calcium supplements simultaneously".split("|"),1,"Correct: Bisphosphonates must be taken on an empty stomach (30–60 minutes before food or other medications) with 8 oz of plain water. Remaining upright for 30 minutes prevents esophageal irritation and ulceration. Incorrect: Taking with food (A) reduces absorption by up to 60%. Lying down (C) increases esophageal erosion risk. Calcium supplements (D) should be separated by at least 30 minutes. Clinical Takeaway: Bisphosphonates reduce fracture risk by inhibiting osteoclast activity. Long-term use (> 5 years) may rarely cause atypical femur fractures and osteonecrosis of the jaw. Exam Pearl: Bisphosphonate names end in '-dronate' (alendronate, risedronate, zoledronate). Zoledronate is given IV annually — alternative for clients who cannot tolerate oral forms.","US"),
  q("NCLEX-RN","Hematology",2,"A nurse is caring for a client with anemia. Which assessment finding is expected?","Bounding pulses and hypertension|Fatigue, pallor, tachycardia, and dyspnea on exertion|Bradycardia and hypertension|Petechiae and prolonged bleeding time".split("|"),1,"Correct: Anemia reduces oxygen-carrying capacity, causing compensatory mechanisms: tachycardia (increased cardiac output), fatigue, pallor (reduced hemoglobin), and dyspnea on exertion (tissues demand more oxygen). Incorrect: Bounding pulses/hypertension (A) suggests fluid overload. Bradycardia (C) is not a compensatory response to anemia. Petechiae and prolonged bleeding (D) suggest thrombocytopenia, not anemia. Clinical Takeaway: Assess Hgb, Hct, RBC count, reticulocyte count, iron studies, B12, and folate to determine anemia type and cause. Treatment depends on the underlying cause. Exam Pearl: Normal hemoglobin: males 14–18 g/dL, females 12–16 g/dL. Hematocrit is approximately 3× the hemoglobin value.","US"),
  q("NCLEX-RN","Renal",4,"A client with acute kidney injury is in the oliguric phase. The nurse should monitor for:","Polyuria and dehydration|Hyperkalemia, fluid overload, metabolic acidosis, and elevated BUN/creatinine|Hypotension and tachycardia only|Normal electrolyte values".split("|"),1,"Correct: The oliguric phase of AKI (urine output < 400 mL/day) causes dangerous accumulation of potassium (hyperkalemia), fluid (pulmonary edema, hypertension), metabolic waste (elevated BUN/creatinine), and hydrogen ions (metabolic acidosis). Incorrect: Polyuria (A) occurs in the diuretic recovery phase. Hypotension alone (C) does not capture the full picture. Electrolytes are NOT normal (D) during the oliguric phase. Clinical Takeaway: Monitor strict I&O, daily weight, serum electrolytes (K+, Na+, Ca²+, PO₄), ABGs, and renal function tests. Fluid restriction and possible dialysis may be needed. Exam Pearl: AKI phases: initiation → oliguric (1–3 weeks, most dangerous) → diuretic (watch for dehydration and electrolyte loss) → recovery (may take up to 1 year for full GFR recovery).","US"),
  q("NCLEX-RN","Pediatrics",2,"A nurse is preparing to administer a vaccination to a 4-month-old infant. The appropriate injection site is the:","Deltoid muscle|Vastus lateralis muscle (anterolateral mid-thigh)|Dorsogluteal muscle|Ventrogluteal muscle".split("|"),1,"Correct: The vastus lateralis (anterolateral mid-thigh) is the recommended IM injection site for infants and children under 12 months because it has the most developed muscle mass and is free of major nerves and blood vessels. Incorrect: Deltoid (A) is not recommended for infants due to small muscle mass; used for children ≥ 12 months. Dorsogluteal (C) is not recommended for any age. Ventrogluteal (D) is preferred in adults and older children but not standard for infants. Clinical Takeaway: Use a 5/8-inch to 1-inch, 22–25 gauge needle for infant IM injections. Hold the thigh firmly during injection. Exam Pearl: CDC recommends: birth–12 months = vastus lateralis. 12 months–2 years = vastus lateralis or deltoid. ≥ 3 years = deltoid preferred.","US"),
  q("NCLEX-RN","Maternal/Newborn",3,"A postpartum client has a temperature of 100.6°F (38.1°C) 48 hours after delivery. The nurse should suspect:","Normal postpartum finding|Postpartum infection (endometritis) requiring assessment and possible antibiotic therapy|Dehydration only|Breast engorgement only".split("|"),1,"Correct: Temperature ≥ 100.4°F (38°C) on any 2 of the first 10 postpartum days (excluding the first 24 hours) defines puerperal fever. Endometritis is the most common postpartum infection. Assess for uterine tenderness, foul-smelling lochia, tachycardia. Incorrect: This is not normal (A). Dehydration (C) and engorgement (D) can cause mild temperature elevation but should not be assumed without ruling out infection. Clinical Takeaway: Risk factors for endometritis: cesarean delivery (highest risk), prolonged labor, PROM, multiple vaginal exams, and retained placental tissue. Treatment: broad-spectrum IV antibiotics (clindamycin + gentamicin). Exam Pearl: The first 24 hours postpartum may have a slight temperature elevation from dehydration — this is not considered pathological. Fever after 24 hours warrants investigation.","US"),
  q("NCLEX-RN","Mental Health",4,"A client with anorexia nervosa is admitted with a BMI of 14. The nurse should be most concerned about:","Body image disturbance|Refeeding syndrome causing potentially fatal cardiac arrhythmias from electrolyte shifts|Social isolation|Constipation".split("|"),1,"Correct: Refeeding syndrome occurs when malnourished clients are fed too rapidly. Insulin release causes intracellular shifts of phosphorus, potassium, and magnesium, leading to hypophosphatemia (most dangerous), cardiac arrhythmias, respiratory failure, seizures, and death. Incorrect: Body image (A) is important but not immediately life-threatening. Social isolation (C) and constipation (D) are lower priority than cardiac arrest risk. Clinical Takeaway: Start feeding slowly ('start low, go slow') with careful monitoring of electrolytes, especially phosphorus. Supplement thiamine before refeeding to prevent Wernicke encephalopathy. Continuous cardiac monitoring is essential. Exam Pearl: Hallmark of refeeding syndrome is hypophosphatemia. Monitor phosphorus, potassium, magnesium, and glucose closely for the first 7–10 days of nutritional rehabilitation.","US"),
];

async function main() {
  let inserted = 0;
  const batchSize = 25;
  for (let i = 0; i < QS.length; i += batchSize) {
    const batch = QS.slice(i, i + batchSize);
    const values: string[] = [];
    const params: any[] = [];
    let idx = 1;
    for (const q of batch) {
      values.push(`($${idx},$${idx+1},$${idx+2},$${idx+3},$${idx+4},$${idx+5}::jsonb,$${idx+6}::jsonb,$${idx+7},$${idx+8}::integer,$${idx+9},$${idx+10},$${idx+11})`);
      params.push(q.tier,q.exam,"multiple_choice","published",q.stem,JSON.stringify(q.options),JSON.stringify([q.correct]),q.rationale,q.diff,q.bs,q.rs,hash(q.stem));
      idx += 12;
    }
    const sql = `INSERT INTO exam_questions (tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, body_system, region_scope, stem_hash)
                 SELECT v.* FROM (VALUES ${values.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash)
                 WHERE NOT EXISTS (SELECT 1 FROM exam_questions e WHERE e.stem_hash = v.stem_hash)`;
    const result = await pool.query(sql, params);
    inserted += result.rowCount || 0;
  }
  console.log(`[RN-B5] Inserted ${inserted}/${QS.length} questions`);

  const countsByRegion = await pool.query(`SELECT region_scope, count(*) as cnt FROM exam_questions WHERE status='published' AND tier='rn' GROUP BY region_scope ORDER BY region_scope`);
  console.log("RN published by region:");
  countsByRegion.rows.forEach((r: any) => console.log(`  ${r.region_scope}: ${r.cnt}`));

  const countsByExam = await pool.query(`SELECT exam, count(*) as cnt FROM exam_questions WHERE status='published' AND tier='rn' GROUP BY exam ORDER BY exam`);
  console.log("RN published by exam:");
  countsByExam.rows.forEach((r: any) => console.log(`  ${r.exam}: ${r.cnt}`));

  const totalRn = await pool.query(`SELECT count(*) as cnt FROM exam_questions WHERE status='published' AND tier='rn'`);
  console.log(`Total published RN questions: ${totalRn.rows[0].cnt}`);

  const tiers = await pool.query(`SELECT tier, count(*) as cnt FROM exam_questions WHERE status='published' GROUP BY tier ORDER BY tier`);
  console.log("All published by tier:");
  tiers.rows.forEach((r: any) => console.log(`  ${r.tier}: ${r.cnt}`));

  await pool.end();
}
main().catch(e => { console.error(e); process.exit(1); });
